-- Schema for Domain: discovery | Business: Pharmaceuticals | Version: v1_ecm
-- Generated on: 2026-05-05 17:50:33

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `pharmaceuticals_ecm`.`discovery` COMMENT 'Owns all data generated during drug discovery and target identification, including high-throughput screening (HTS) results, structure-activity relationship (SAR) analysis, mechanism of action (MOA) studies, hit-to-lead progression, molecular targets, and early-stage compound optimization under GLP. Manages research data from electronic lab notebooks (ELN) in IDBS/Dotmatics, assay results, and compound libraries. Authoritative source for NCE (New Chemical Entity) and NBE (New Biological Entity) research data entering the development pipeline.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`molecular_target` (
    `molecular_target_id` BIGINT COMMENT 'Unique surrogate identifier for the molecular target record in the discovery data product. Primary key for all downstream joins and lineage tracking.',
    `drug_substance_id` BIGINT COMMENT 'Foreign key linking to product.drug_substance. Business justification: Target-based portfolio analysis: links validated biological target to marketed API for competitive intelligence, patent landscape assessment, MOA-based product clustering. Supports freedom-to-operate ',
    `gxp_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.gxp_obligation. Business justification: Target validation studies must comply with specific GxP obligations (GLP for preclinical, 21 CFR Part 11 for electronic records). Obligation linkage ensures regulatory defensibility of validation data',
    `patent_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent. Business justification: Molecular targets are patented inventions requiring patent protection tracking for freedom-to-operate analysis, portfolio management, and competitive intelligence in target selection decisions.',
    `patent_claim_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_claim. Business justification: Specific patent claims cover target modulation methods; claim-level tracking required for FTO clearance, licensing negotiations, and assessing blocking IP in target validation stage gates.',
    `competitive_landscape_summary` STRING COMMENT 'Summary of known competitive programs targeting this molecular target, including approved drugs, clinical-stage compounds, and disclosed research programs from competitor organizations. Business-confidential intelligence used for portfolio strategy.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this molecular target record was first created in the discovery data product. Supports audit trail, data lineage, and 21 CFR Part 11 electronic records compliance.',
    `discovery_program_code` STRING COMMENT 'Internal program or project code under which this target is being investigated. Links the target to the broader drug discovery program for portfolio management, resource allocation, and P&L tracking.',
    `disease_association` STRING COMMENT 'Specific disease or condition(s) associated with this molecular target, as supported by published literature or internal research data. May reference ICD-10/ICD-11 disease codes or MeSH disease terms.',
    `druggability_assessment` STRING COMMENT 'Scientific assessment of the targets amenability to small molecule or biologic modulation based on structural, biochemical, and computational analyses. Key input to portfolio prioritization and NCE/NBE strategy decisions.. Valid values are `highly_druggable|druggable|moderately_druggable|challenging|undruggable|unknown`',
    `eln_notebook_reference` STRING COMMENT 'Reference identifier to the primary Electronic Lab Notebook (ELN) experiment record in IDBS E-WorkBook or Dotmatics that documents the original target identification and characterization data. Provides full scientific audit trail.',
    `ensembl_gene_code` STRING COMMENT 'Ensembl stable gene identifier (e.g., ENSG00000146648) for the gene encoding the molecular target. Used for genomic cross-referencing, variant analysis, and bioinformatics pipelines.. Valid values are `^ENSG[0-9]{11}$`',
    `expression_tissue` STRING COMMENT 'Primary tissue(s) or cell type(s) where this molecular target is expressed at therapeutically relevant levels, as determined by transcriptomic or proteomic profiling (e.g., liver, lung epithelium, T-cells). Informs tissue selectivity and delivery strategy.',
    `first_disclosed_date` DATE COMMENT 'Date on which this molecular target was first formally disclosed or documented in the internal ELN or target identification database. Establishes the scientific priority date for IP purposes.',
    `gene_name` STRING COMMENT 'Official HGNC (HUGO Gene Nomenclature Committee) approved gene symbol encoding the molecular target (e.g., EGFR, TP53, BRCA1). Standard identifier used in regulatory submissions and scientific publications.',
    `genetic_association_score` DECIMAL(18,2) COMMENT 'Quantitative score (0.0000–1.0000) representing the strength of genetic evidence linking this target to the associated disease, derived from GWAS, Mendelian randomization, or Open Targets Platform data. Higher scores indicate stronger genetic validation.',
    `indication_code` STRING COMMENT 'ICD-11 (International Classification of Diseases, 11th Revision) code for the primary indication associated with this target. Enables standardized cross-referencing with regulatory submissions and clinical trial registries.. Valid values are `^[A-Z][0-9]{2}(.[0-9]{1,4})?$`',
    `last_reviewed_date` DATE COMMENT 'Date of the most recent scientific or portfolio review of this target record. Ensures data currency and supports periodic target triage processes.',
    `moa_description` STRING COMMENT 'Narrative description of the molecular mechanism by which modulation of this target is expected to produce a therapeutic effect. Captures agonism, antagonism, inhibition, activation, or allosteric modulation details as documented in ELN.',
    `moa_type` STRING COMMENT 'Categorical classification of the pharmacological mechanism of action for compounds acting on this target. Used to group targets by intervention strategy in SAR analysis and portfolio reporting. [ENUM-REF-CANDIDATE: agonist|antagonist|inhibitor|activator|allosteric_modulator|degrader|other — 7 candidates stripped; promote to reference product]',
    `modality` STRING COMMENT 'Preferred drug modality for targeting this molecular target based on its structural and biochemical properties. Determines the NCE (New Chemical Entity) or NBE (New Biological Entity) classification of resulting compounds. [ENUM-REF-CANDIDATE: small_molecule|biologic|antibody|peptide|oligonucleotide|cell_therapy|gene_therapy|other — 8 candidates stripped; promote to reference product]',
    `novelty_status` STRING COMMENT 'Classification of the targets novelty relative to the competitive landscape. Novel targets represent first-in-class opportunities; established targets have existing approved drugs; repurposed targets are being explored in new indications.. Valid values are `novel|established|repurposed|competitive`',
    `organism` STRING COMMENT 'Biological organism in which the molecular target is expressed and studied. Typically Homo sapiens for human targets, but may include model organisms used in preclinical validation studies.. Valid values are `Homo sapiens|Mus musculus|Rattus norvegicus|other`',
    `patent_landscape_summary` STRING COMMENT 'High-level summary of the patent landscape around this molecular target, including freedom-to-operate (FTO) considerations and known composition-of-matter or method-of-use patents. Supports IP strategy decisions.',
    `pathway_name` STRING COMMENT 'Name of the primary biological signaling or metabolic pathway in which this target participates (e.g., PI3K/AKT/mTOR, RAS/MAPK, JAK/STAT). Supports pathway-based target clustering and polypharmacology analysis.',
    `pdb_code` STRING COMMENT 'RCSB Protein Data Bank accession code for the primary 3D structure of this molecular target. Used by computational chemistry and structure-based drug design (SBDD) teams for molecular docking and virtual screening.. Valid values are `^[0-9][A-Z0-9]{3}$`',
    `prioritization_tier` STRING COMMENT 'Portfolio prioritization tier assigned to this target by the Target Selection Committee, reflecting strategic importance, scientific confidence, and commercial potential. Tier 1 targets receive maximum resource allocation.. Valid values are `tier_1|tier_2|tier_3|deprioritized`',
    `protein_structure_available` BOOLEAN COMMENT 'Indicates whether a resolved 3D protein structure (X-ray crystallography, cryo-EM, or NMR) is available for this target in the Protein Data Bank (PDB) or internal structural biology repository. Directly impacts structure-based drug design (SBDD) feasibility.',
    `safety_concern_description` STRING COMMENT 'Narrative description of identified safety liabilities associated with modulation of this target (e.g., hERG channel activity, hepatotoxicity risk, immunosuppression). Populated only when safety_concern_flag is True.',
    `safety_concern_flag` BOOLEAN COMMENT 'Indicates whether known safety liabilities or toxicological concerns have been identified for this target based on literature, genetic association studies, or internal preclinical data. Triggers mandatory safety review before progression.',
    `selectivity_profile` STRING COMMENT 'Assessment of the targets selectivity relative to related family members or off-target proteins. Informs compound design strategy to minimize off-target toxicity and maximize therapeutic index.. Valid values are `highly_selective|selective|moderately_selective|pan_inhibitor|unknown`',
    `target_class` STRING COMMENT 'Pharmacological class of the molecular target based on its biochemical function and structural family. Drives druggability assessment strategy and compound screening cascade design. [ENUM-REF-CANDIDATE: GPCR|kinase|nuclear_receptor|ion_channel|protease|phosphatase|epigenetic_regulator|transcription_factor|transporter|other — promote to reference product]',
    `target_code` STRING COMMENT 'Internally assigned alphanumeric business identifier for the molecular target, used as the externally-known unique code across systems (ELN, LIMS, CTMS). Distinct from the surrogate PK and from external database accession numbers.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `target_engagement_assay` STRING COMMENT 'Name or identifier of the primary biochemical or biophysical assay used to measure compound engagement with this target (e.g., HTRF binding assay, SPR, ITC, NanoBRET). Registered in LIMS (LabWare/SampleManager) and ELN.',
    `target_name` STRING COMMENT 'Human-readable scientific name of the molecular target (e.g., EGFR, BRAF, PD-L1, CDK4/6). Serves as the primary identity label used by research scientists and in ELN records within IDBS/Dotmatics.',
    `target_owner` STRING COMMENT 'Name or employee identifier of the principal scientist or research team lead responsible for this molecular target within the discovery organization. Accountable for target validation decisions and data quality.',
    `target_type` STRING COMMENT 'Biological molecule type of the target (e.g., protein, enzyme, receptor, ion channel, nucleic acid). Determines the modality of drug intervention and screening assay design. [ENUM-REF-CANDIDATE: protein|enzyme|receptor|ion_channel|nucleic_acid|lipid|carbohydrate|other — 8 candidates stripped; promote to reference product]',
    `therapeutic_area` STRING COMMENT 'Primary therapeutic area or disease domain for which this target is being investigated (e.g., Oncology, Immunology, Rare Diseases, Neuroscience, Cardiovascular). Aligns with the companys portfolio strategy and pipeline reporting. [ENUM-REF-CANDIDATE: oncology|immunology|rare_disease|neuroscience|cardiovascular|infectious_disease|metabolic|respiratory|other — promote to reference product]',
    `uniprot_accession` STRING COMMENT 'Universal Protein Resource (UniProt) accession number uniquely identifying the protein target in the global UniProtKB database. Enables cross-referencing with external biological databases and regulatory submissions.. Valid values are `^[A-Z][0-9][A-Z0-9]{3}[0-9]$|^[A-Z][0-9][A-Z0-9]{3}[0-9]-[0-9]+$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this molecular target record. Used for incremental data pipeline processing, change detection, and audit trail maintenance per 21 CFR Part 11.',
    `validation_completion_date` DATE COMMENT 'Date on which target validation studies were completed and the target was formally declared validated (in vitro or in vivo). Marks the transition from target identification to hit-to-lead progression stage.',
    `validation_status` STRING COMMENT 'Current lifecycle stage of target validation, reflecting the level of scientific evidence supporting the targets role in disease. Drives go/no-go decisions for hit-to-lead progression. [ENUM-REF-CANDIDATE: identified|hypothetical|validated_in_vitro|validated_in_vivo|clinically_validated|deprioritized — promote to reference product]. Valid values are `identified|hypothetical|validated_in_vitro|validated_in_vivo|clinically_validated|deprioritized`',
    CONSTRAINT pk_molecular_target PRIMARY KEY(`molecular_target_id`)
) COMMENT 'Master record for biological molecular targets identified during drug discovery, including proteins, enzymes, receptors, ion channels, and nucleic acids. Captures target class, gene name, UniProt/Ensembl identifiers, mechanism of action (MOA), therapeutic area relevance, target validation status, druggability assessment, and disease association. Authoritative SSOT for all target identification data entering the discovery pipeline from IDBS/Dotmatics ELN.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`compound` (
    `compound_id` BIGINT COMMENT 'Unique system-generated surrogate key for each compound record in the discovery compound library. Primary key for the compound master data product.',
    `drug_master_file_id` BIGINT COMMENT 'Foreign key linking to intellectual.drug_master_file. Business justification: Compounds (APIs) are covered by DMFs for regulatory submissions; linkage supports IND/NDA filings, tracks manufacturing site authorization, and enables CMC strategy coordination between discovery and ',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Portfolio management necessity: links discovery compound directly to formulated product for development tracking, IP-to-product mapping, and commercial forecasting. Supports stage-gate decisions, pate',
    `drug_substance_id` BIGINT COMMENT 'Foreign key linking to product.drug_substance. Business justification: Regulatory CMC requirement: IND/NDA submissions must trace marketed API back to discovery compound for chemistry documentation. Critical for candidate nomination handoff, regulatory filing preparation',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Compounds progressing to development/manufacturing are registered as materials in ERP for procurement, inventory management, batch tracking, and supply chain planning. Critical integration point betwe',
    `part11_system_id` BIGINT COMMENT 'Foreign key linking to compliance.part11_system. Business justification: Compounds are registered and managed in Part 11-compliant systems (ELN, LIMS, registration databases). System assignment enables audit trail verification, electronic signature validation, and inspecti',
    `patent_claim_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_claim. Business justification: Compounds must link to patent claims to track IP protection. This is essential for pharmaceutical asset valuation and freedom-to-operate analysis. No visible redundant columns to remove.',
    `patent_family_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_family. Business justification: Compounds belong to patent families covering composition-of-matter globally; family-level tracking supports international IP strategy, prosecution coordination, and portfolio valuation for business de',
    `patent_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent. Business justification: Compounds are patented chemical matter requiring direct patent linkage for IP lifecycle management, orange book listing preparation, patent term extension applications, and generic entry risk assessme',
    `trademark_id` BIGINT COMMENT 'Foreign key linking to intellectual.trademark. Business justification: Compounds (branded products) require trademark protection; linkage tracks brand strategy, supports naming decisions, coordinates trademark filing with development timelines, and protects commercial id',
    `atc_code` STRING COMMENT 'WHO Anatomical Therapeutic Chemical (ATC) classification code assigned to the compound based on its therapeutic use and pharmacological properties. Used for market access analysis, competitive benchmarking, and regulatory submissions. May be provisional at early discovery stage.. Valid values are `^[A-Z][0-9]{2}[A-Z]{2}[0-9]{2}$`',
    `cas_number` STRING COMMENT 'Globally unique Chemical Abstracts Service (CAS) registry number assigned by the American Chemical Society to uniquely identify the chemical substance. Used for regulatory submissions, procurement, and cross-system compound lookup.. Valid values are `^[0-9]{2,7}-[0-9]{2}-[0-9]$`',
    `compound_class` STRING COMMENT 'Broad classification of the compound by molecular modality. Drives regulatory pathway selection (NDA vs BLA), manufacturing strategy (chemical synthesis vs biologics), and analytical method requirements. [ENUM-REF-CANDIDATE: small_molecule|biologic|peptide|adc|oligonucleotide|cell_therapy|rna_therapy|gene_therapy — promote to reference product]. Valid values are `small_molecule|biologic|peptide|adc|oligonucleotide|cell_therapy`',
    `compound_name` STRING COMMENT 'Internal working name or code name assigned to the compound during discovery (e.g., project code name such as ABC-1234). Used as the primary human-readable label in ELN, LIMS, and CTMS systems before an INN or USAN is assigned.',
    `compound_status` STRING COMMENT 'Current lifecycle status of the compound within the discovery pipeline. Active indicates the compound is under active research; promoted indicates advancement to preclinical or clinical development; discontinued indicates the compound has been deprioritized or terminated.. Valid values are `active|inactive|on_hold|discontinued|promoted|archived`',
    `controlled_substance_schedule` STRING COMMENT 'U.S. Drug Enforcement Administration (DEA) controlled substance schedule classification for the compound (Schedule I–V or not controlled). Determines handling, storage, procurement, and regulatory reporting requirements under the Controlled Substances Act.. Valid values are `schedule_i|schedule_ii|schedule_iii|schedule_iv|schedule_v|not_controlled`',
    `created_timestamp` TIMESTAMP COMMENT 'System-generated timestamp recording when the compound record was first created in the data platform (Silver Layer). Supports audit trail requirements under 21 CFR Part 11 and data lineage tracking in the Databricks Lakehouse.',
    `discovery_stage` STRING COMMENT 'Current stage of the compound within the drug discovery pipeline. Tracks progression from target identification through hit identification, hit-to-lead, lead optimization, and candidate selection before IND filing. Used for portfolio reporting and stage-gate decision making.. Valid values are `target_id|hit_identification|hit_to_lead|lead_optimization|candidate_selection|preclinical`',
    `eln_reference_code` STRING COMMENT 'Reference identifier linking this compound record to the originating experiment or notebook entry in the Electronic Lab Notebook (ELN) system (IDBS E-WorkBook or Dotmatics). Provides traceability from the compound master record back to the primary research data and synthesis records.',
    `entity_type` STRING COMMENT 'Regulatory classification of the compound as a New Chemical Entity (NCE), New Biological Entity (NBE), biosimilar, fixed-dose combination, or prodrug. Determines regulatory exclusivity periods, patent strategy, and submission pathway under FDA, EMA, and ICH guidelines.. Valid values are `nce|nbe|biosimilar|fixed_dose_combination|prodrug`',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether the compound and its associated research data have been generated under Good Laboratory Practice (GLP) conditions as required for regulatory submissions. GLP compliance is mandatory for safety pharmacology and toxicology studies supporting IND applications.',
    `hazard_classification` STRING COMMENT 'Globally Harmonized System (GHS) hazard classification for the compound covering health, physical, and environmental hazards (e.g., Acute Toxicity Cat. 2, Carcinogen Cat. 1A). Required for Safety Data Sheet (SDS) preparation, occupational health risk assessment, and EHS compliance.',
    `hba_count` STRING COMMENT 'Number of hydrogen bond acceptors (HBA) in the compound structure. Key Lipinski Rule of Five parameter (threshold: ≤ 10 HBAs) used in drug-likeness assessment and oral bioavailability prediction during hit-to-lead and lead optimization.',
    `hbd_count` STRING COMMENT 'Number of hydrogen bond donors (HBD) in the compound structure. Key Lipinski Rule of Five parameter (threshold: ≤ 5 HBDs) used in drug-likeness assessment and oral bioavailability prediction during hit-to-lead and lead optimization.',
    `inchi` STRING COMMENT 'IUPAC International Chemical Identifier (InChI) string providing a standardized, layered representation of the compounds chemical structure. Used for cross-system compound deduplication, registry lookups, and interoperability with external databases (PubChem, ChEMBL). Classified confidential as it encodes proprietary structural IP.',
    `inchi_key` STRING COMMENT 'Fixed-length 27-character hashed representation of the InChI string (InChIKey). Used as a compact, searchable identifier for compound lookup in external databases (PubChem, ChEMBL, CAS SciFinder) and for deduplication across compound registries.. Valid values are `^[A-Z]{14}-[A-Z]{10}-[A-Z]$`',
    `inn` STRING COMMENT 'World Health Organization (WHO)-assigned International Nonproprietary Name (INN) for the active pharmaceutical ingredient. Used in regulatory submissions (NDA, BLA, MAA) and scientific communications. May be null for early-stage compounds not yet assigned an INN.',
    `iupac_name` STRING COMMENT 'Systematic chemical name of the compound following International Union of Pure and Applied Chemistry (IUPAC) nomenclature rules. Provides an unambiguous, internationally recognized chemical identity for regulatory submissions and scientific publications.',
    `last_reviewed_date` DATE COMMENT 'Date on which the compound record was last reviewed by a qualified scientist or data steward for accuracy, completeness, and continued relevance in the discovery portfolio. Supports data governance and periodic compound library curation activities.',
    `library_membership` STRING COMMENT 'Designation of the compound library or collection to which this compound belongs within the corporate compound library management system. Drives screening campaign design, compound availability, and resource allocation in HTS and fragment-based drug discovery programs.. Valid values are `hts_library|fragment_library|lead_library|natural_product_library|focused_library|tool_compound`',
    `logp` DECIMAL(18,2) COMMENT 'Logarithm of the octanol-water partition coefficient (LogP), a measure of the compounds lipophilicity. Critical SAR and ADME parameter used to predict membrane permeability, oral bioavailability, and CNS penetration. Lipinski Rule of Five threshold: LogP ≤ 5.',
    `mechanism_of_action` STRING COMMENT 'Described mechanism of action (MOA) of the compound — the biochemical interaction through which the compound produces its pharmacological effect (e.g., selective inhibitor of EGFR tyrosine kinase). Critical for target validation, patent claims, and regulatory submissions.',
    `molecular_formula` STRING COMMENT 'Empirical molecular formula of the compound expressed using Hill notation (e.g., C21H30N2O5). Represents the elemental composition and is used in regulatory submissions, analytical method development, and structural verification.. Valid values are `^([A-Z][a-z]?[0-9]*)+$`',
    `molecular_weight` DECIMAL(18,2) COMMENT 'Average molecular weight of the compound expressed in grams per mole (g/mol). Critical physicochemical property used in SAR analysis, ADME profiling, formulation development, and Lipinski Rule of Five drug-likeness assessment.',
    `physical_state` STRING COMMENT 'Physical state of the compound at standard conditions (solid, liquid, gas, semi-solid). Determines handling procedures, formulation approach, and storage requirements. Captured in the ELN and LIMS at time of compound registration.. Valid values are `solid|liquid|gas|semi_solid`',
    `primary_target` STRING COMMENT 'Primary biological molecular target of the compound (e.g., gene name, protein name, receptor, enzyme — such as EGFR, PD-1, BCL-2). Used in target identification, SAR analysis, and cross-compound target coverage analysis within the discovery portfolio.',
    `purity_percent` DECIMAL(18,2) COMMENT 'Measured chemical purity of the compound expressed as a percentage (0.00–100.00%). Determined by analytical methods such as HPLC or NMR. Critical quality attribute (CQA) for assay reliability, GLP compliance, and advancement decisions in hit-to-lead progression.',
    `registration_date` DATE COMMENT 'Date on which the compound was formally registered in the corporate compound registry (IDBS/Dotmatics). Marks the official entry of the compound into the discovery compound library and initiates the compound lifecycle tracking.',
    `registration_number` STRING COMMENT 'Internally assigned unique registration number for the compound within the corporate compound registry (e.g., IDBS/Dotmatics compound registration system). Serves as the primary business identifier used across discovery, CMC, and regulatory workflows.',
    `rotatable_bond_count` STRING COMMENT 'Number of rotatable bonds in the compound structure. Veber rule parameter (threshold: ≤ 10) used alongside TPSA to predict oral bioavailability and molecular flexibility in SAR and lead optimization analyses.',
    `smiles` STRING COMMENT 'Canonical SMILES (Simplified Molecular Input Line Entry System) string representing the two-dimensional chemical structure of the compound. Used in cheminformatics, HTS data analysis, SAR modeling, and AI/ML-based drug discovery workflows. Classified confidential as it encodes proprietary structural IP.',
    `solubility_aqueous_um` DECIMAL(18,2) COMMENT 'Measured or predicted aqueous solubility of the compound expressed in micromolar (µM). Key ADME physicochemical property used in SAR analysis, formulation feasibility assessment, and drug-likeness profiling (Lipinski, Veber rules).',
    `source_type` STRING COMMENT 'Origin classification of the compound indicating how it was obtained. Synthesized compounds are produced in-house; purchased compounds are acquired from external vendors or CROs; natural products are derived from biological sources. Impacts IP strategy and CMC documentation.. Valid values are `synthesized|purchased|natural_product|fermentation|semi_synthetic`',
    `storage_condition` STRING COMMENT 'Recommended storage conditions for the compound (e.g., -20°C, under nitrogen, protected from light, desiccated). Ensures compound stability and integrity in the compound library. Derived from stability data and referenced in CoA and compound library management SOPs.',
    `therapeutic_area` STRING COMMENT 'Primary therapeutic area or disease indication for which the compound is being developed (e.g., Oncology, Immunology, Rare Diseases, Neuroscience, Cardiovascular). Aligns with the ATC classification system and drives portfolio prioritization and resource allocation decisions.',
    `tpsa_angstrom2` DECIMAL(18,2) COMMENT 'Topological Polar Surface Area (TPSA) of the compound expressed in square angstroms (Å²). Used to predict intestinal absorption, blood-brain barrier penetration, and oral bioavailability. Veber rule threshold: TPSA ≤ 140 Å² for oral drugs.',
    `updated_timestamp` TIMESTAMP COMMENT 'System-generated timestamp recording when the compound record was last modified in the data platform. Supports audit trail requirements under 21 CFR Part 11 and enables change detection for downstream data consumers and AI/ML pipelines.',
    `usan` STRING COMMENT 'United States Adopted Name (USAN) assigned by the USAN Council for the compound. Used in US regulatory submissions (NDA/BLA) and US commercial labeling. May differ slightly from INN.',
    `vendor_catalog_number` STRING COMMENT 'Vendor-assigned catalog or product number for purchased compounds. Used for reorder, procurement traceability, and cross-referencing with vendor CoA and SDS documentation. Applicable only when source_type is purchased.',
    `vendor_name` STRING COMMENT 'Name of the external vendor, CRO, or supplier from whom the compound was purchased or sourced, if applicable. Relevant for purchased compounds and natural product extracts. Used for procurement traceability, vendor qualification, and supply chain management.',
    CONSTRAINT pk_compound PRIMARY KEY(`compound_id`)
) COMMENT 'Master record for all chemical and biological compounds in the discovery compound library, including NCEs (New Chemical Entities) and NBEs (New Biological Entities). Captures compound identity (IUPAC name, INN/USAN, registration number, CAS number), structural representation (molecular formula, molecular weight, SMILES, InChI), compound class (small molecule, biologic, peptide, ADC), source (synthesized, purchased, natural product), physicochemical properties (purity, physical state, storage conditions), and library membership. Authoritative SSOT for compound identity and structure across the discovery domain.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`assay` (
    `assay_id` BIGINT COMMENT 'Unique surrogate identifier for the assay master record in the discovery domain. Primary key for the assay data product. Role classification: MASTER_RESOURCE.',
    `gxp_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.gxp_obligation. Business justification: Assays used for regulatory submissions must comply with specific GxP obligations (GLP validation, data integrity, method validation). Obligation mapping drives validation requirements, inspection prep',
    `molecular_target_id` BIGINT COMMENT 'Foreign key linking to discovery.molecular_target. Business justification: Assays are designed to screen against specific molecular targets. The assay table currently has target_name and target_class as denormalized STRING attributes. Adding molecular_target_id FK allows joi',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: GxP compliance and regulatory inspections require traceable accountability for assay validation and execution. Responsible scientist must link to qualified employee record for training verification, e',
    `assay_code` STRING COMMENT 'Externally-known, human-readable unique code assigned to the assay within the ELN or LIMS (e.g., ASY-HTS0042). Serves as the BUSINESS_IDENTIFIER category for MASTER_RESOURCE role. Used for cross-system referencing between IDBS/Dotmatics, LabWare LIMS, and SAP QM.. Valid values are `^ASY-[A-Z0-9]{4,12}$`',
    `assay_name` STRING COMMENT 'Full descriptive name of the assay as registered in the ELN (e.g., EGFR Kinase Inhibition HTRF Assay). Serves as the IDENTITY_LABEL category for MASTER_RESOURCE role. Used in scientific reports, regulatory submissions, and compound screening dashboards.',
    `assay_type` STRING COMMENT 'Primary scientific classification of the assay based on its biological or chemical mode of measurement. Serves as the CLASSIFICATION_OR_TYPE category for MASTER_RESOURCE role. Drives downstream SAR analysis workflows and compound triage decisions. [ENUM-REF-CANDIDATE: biochemical|cell_based|phenotypic|ADME|toxicity|binding|functional — promote to reference product]',
    `automation_compatible` BOOLEAN COMMENT 'Indicates whether the assay has been adapted and validated for automated liquid handling platforms (e.g., Hamilton, Tecan, Beckman Coulter). Determines eligibility for inclusion in HTS screening campaigns and impacts throughput capacity planning.',
    `cell_line` STRING COMMENT 'Name of the cell line used in cell-based assays (e.g., HEK293, HeLa, Jurkat, A549, MCF-7). Null for biochemical or cell-free assays. Required for assay reproducibility and cross-site comparability. Cell line authentication records are maintained in the ELN.',
    `coefficient_of_variation_pct` DECIMAL(18,2) COMMENT 'Percentage coefficient of variation (%CV) of the assay signal across replicate measurements, representing assay precision and reproducibility. Typically required to be ≤ 15% for HTS assays and ≤ 20% for bioanalytical assays per ICH Q2(R1). Stored from the assay validation run.',
    `concentration_unit` STRING COMMENT 'Unit of measurement for compound concentrations used in the assay (e.g., nM, µM, mM). Standardizes concentration reporting across compound screening results and SAR analysis. Required for dose-response curve fitting and IC50/EC50 calculations. [ENUM-REF-CANDIDATE: nM|uM|mM|mg_mL|ug_mL|ng_mL|pM — 7 candidates stripped; promote to reference product]',
    `cost_per_well_usd` DECIMAL(18,2) COMMENT 'Estimated reagent and consumable cost per assay well in US dollars. Used for screening campaign cost modeling, budget planning, and make-vs-buy decisions for outsourcing to CROs. Sourced from SAP S/4HANA MM procurement data and lab supply records.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the assay master record was first created in the ELN or data platform. Serves as the RECORD_AUDIT_CREATED category for MASTER_RESOURCE role. Required for 21 CFR Part 11 electronic records compliance and data lineage tracking.',
    `cro_vendor_name` STRING COMMENT 'Name of the external Contract Research Organization (CRO) executing this assay when outsourced_to_cro is true. Null for in-house assays. Used for vendor performance tracking, contract management, and regulatory audit trail documentation.',
    `detection_method` STRING COMMENT 'Physical or chemical detection principle used to measure the assay signal (e.g., fluorescence, luminescence, radioactivity, mass spectrometry). Distinct from technology_platform — platform is the instrument system, detection_method is the underlying measurement principle. Used for assay validation documentation and GLP compliance records. [ENUM-REF-CANDIDATE: fluorescence|luminescence|absorbance|radioactivity|mass_spectrometry|NMR|SPR|calorimetry — promote to reference product]',
    `eln_notebook_reference` STRING COMMENT 'Identifier of the Electronic Lab Notebook (ELN) experiment or notebook entry in IDBS E-WorkBook or Dotmatics where the assay development and validation data are recorded. Provides direct traceability from the data product to the source scientific record.',
    `first_used_date` DATE COMMENT 'Date when the assay was first deployed for compound screening or profiling activities. Marks the operational start of the assay lifecycle. Used for assay age tracking, periodic revalidation scheduling, and portfolio lifecycle management.',
    `format` STRING COMMENT 'Operational format describing how the assay is run in the screening workflow (e.g., High-Throughput Screening (HTS) primary screen, dose-response, selectivity panel). Determines throughput capacity planning and compound consumption requirements.. Valid values are `HTS|dose_response|selectivity|counter_screen|orthogonal|confirmatory`',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether the assay is conducted under Good Laboratory Practice (GLP) regulations as required for regulatory submissions (IND/NDA/BLA). GLP-compliant assays require full audit trails, validated equipment, and certified personnel. Critical for preclinical safety study data submitted to FDA/EMA.',
    `hit_threshold_unit` STRING COMMENT 'Unit of measurement for the hit_threshold_value (e.g., percent inhibition, nM IC50). Ensures unambiguous interpretation of the hit-calling criterion across different assay types and readout formats.. Valid values are `percent_inhibition|percent_activation|nM|uM|ratio|fold_change`',
    `hit_threshold_value` DECIMAL(18,2) COMMENT 'Numerical threshold used to classify a compound as a hit in primary screening (e.g., ≥ 50% inhibition at 10 µM). Defined during assay validation and used by automated hit-calling algorithms in the HTS data analysis pipeline. Critical for hit-to-lead progression decisions.',
    `incubation_time_hours` DECIMAL(18,2) COMMENT 'Standard incubation duration in hours for the assay reaction or cell treatment step. Critical for assay reproducibility and scheduling of automated liquid handling workflows. Stored from the validated assay protocol.',
    `last_validated_date` DATE COMMENT 'Date of the most recent formal validation or requalification of the assay per ICH Q2(R1) or fit-for-purpose qualification criteria. Used to trigger periodic revalidation workflows and to assess whether assay data is current for regulatory submissions.',
    `lims_assay_code` STRING COMMENT 'Cross-reference identifier for this assay in the Laboratory Information Management System (LIMS) — LabWare or Thermo Fisher SampleManager. Enables bidirectional traceability between the discovery data product and the LIMS assay execution records.',
    `multiplexed` BOOLEAN COMMENT 'Indicates whether the assay measures multiple analytes or endpoints simultaneously in a single well or reaction (multiplexed assay). Multiplexed assays increase data density per compound and reduce reagent consumption. Relevant for assay cost modeling and data analysis pipeline configuration.',
    `outsourced_to_cro` BOOLEAN COMMENT 'Indicates whether this assay is currently outsourced to an external Contract Research Organization (CRO) for execution. When true, the cro_vendor_name field captures the CRO identity. Impacts data governance, IP ownership, and regulatory audit trail requirements.',
    `owning_department` STRING COMMENT 'Name of the research department or functional group that owns and maintains the assay (e.g., HTS Group, In Vitro Pharmacology, ADME Sciences, Toxicology). Used for resource allocation, cost center attribution, and assay portfolio governance.',
    `plate_format` STRING COMMENT 'Microplate format used in the assay (e.g., 96-well, 384-well, 1536-well). Determines reagent volumes, automation compatibility, and throughput capacity. Critical for liquid handling robot programming and compound dispensing protocols.. Valid values are `96_well|384_well|1536_well|24_well|48_well`',
    `protocol_reference` STRING COMMENT 'Document identifier or URL reference to the Standard Operating Procedure (SOP) or assay protocol document stored in the ELN (IDBS/Dotmatics) or document management system (Veeva Vault QualityDocs). Ensures traceability from assay execution to the governing protocol version.',
    `protocol_version` STRING COMMENT 'Version number of the assay protocol document in effect at the time of assay execution (e.g., v1.0, v2.3). Required for GLP audit trails and regulatory submission traceability. Distinct from protocol_reference which is the document identifier.. Valid values are `^vd+.d+$`',
    `readout_type` STRING COMMENT 'Primary quantitative output metric reported by the assay (e.g., IC50, EC50, Ki, Kd, percent inhibition, percent activation). Determines how compound activity data is interpreted in SAR analysis and hit-to-lead progression decisions. [ENUM-REF-CANDIDATE: IC50|EC50|Ki|Kd|percent_inhibition|percent_activation|ratio|count|viability_pct — promote to reference product]',
    `regulatory_submission_eligible` BOOLEAN COMMENT 'Indicates whether assay results generated using this assay are eligible for inclusion in regulatory submissions (IND, NDA, BLA, MAA). Eligibility requires full validation per ICH Q2(R1) and GLP compliance where applicable. Governs data governance workflows for regulatory data packages.',
    `retirement_date` DATE COMMENT 'Date when the assay was formally retired and removed from active use. Null for active assays. Retirement is triggered by target deprioritization, supersession by a superior assay, or platform decommissioning. Required for data governance and historical data archival.',
    `signal_window` DECIMAL(18,2) COMMENT 'Ratio of the maximum signal (positive control) to the minimum signal (negative control), quantifying the dynamic range of the assay. A signal window ≥ 2 is typically required for HTS qualification. Used in assay validation reports and Z-factor calculations.',
    `species_origin` STRING COMMENT 'Biological species from which the assay target, cells, or biological material is derived (e.g., human, mouse, rat, recombinant). Critical for translational relevance assessment and cross-species selectivity profiling. Impacts regulatory acceptability of preclinical data for IND submissions. [ENUM-REF-CANDIDATE: human|mouse|rat|rabbit|dog|monkey|in_vitro_recombinant — 7 candidates stripped; promote to reference product]',
    `technology_platform` STRING COMMENT 'Detection technology or instrument platform used to execute the assay (e.g., HTRF, AlphaScreen, Surface Plasmon Resonance (SPR), NMR, FRET, TR-FRET, Luminescence, Flow Cytometry). Critical for assay reproducibility assessment and equipment scheduling. [ENUM-REF-CANDIDATE: HTRF|AlphaScreen|SPR|NMR|FRET|TR-FRET|luminescence|flow_cytometry|mass_spectrometry|fluorescence_polarization — promote to reference product]',
    `temperature_celsius` DECIMAL(18,2) COMMENT 'Standard incubation or reaction temperature in degrees Celsius for the assay. Critical for assay reproducibility across sites and instruments. Deviations from this value are flagged as out-of-specification (OOS) events in the LIMS.',
    `therapeutic_area` STRING COMMENT 'Disease or therapeutic area that the assay supports (e.g., Oncology, Immunology, Rare Diseases, Neuroscience, Cardiovascular). Links assay activity to the business portfolio and pipeline planning. [ENUM-REF-CANDIDATE: oncology|immunology|rare_diseases|neuroscience|cardiovascular|infectious_diseases|metabolic — promote to reference product]',
    `throughput_capacity` STRING COMMENT 'Maximum number of compounds or samples that can be processed per day using this assay under standard HTS conditions. Serves as the MEASUREMENT_OR_VALUE category for MASTER_RESOURCE role. Used for compound library screening campaign planning and resource scheduling in the discovery lab.',
    `validation_status` STRING COMMENT 'Current lifecycle state of the assay with respect to its scientific and regulatory validation. Serves as the LIFECYCLE_STATUS category for MASTER_RESOURCE role. validated indicates full ICH Q2(R1) compliance; qualified indicates fit-for-purpose qualification; development indicates the assay is still being optimized. Governs whether assay results can be used in regulatory submissions.. Valid values are `development|qualified|validated|retired|on_hold`',
    `z_prime_factor` DECIMAL(18,2) COMMENT 'Statistical measure of assay quality (Z) calculated from positive and negative control variability. Values ≥ 0.5 indicate an excellent assay suitable for HTS. Stored as the validated Z from the assay qualification run. Used to gate assay deployment for compound screening campaigns.',
    CONSTRAINT pk_assay PRIMARY KEY(`assay_id`)
) COMMENT 'Master record for biological and biochemical assays used in drug discovery screening and profiling. Captures assay name, assay type (biochemical, cell-based, phenotypic, ADME, toxicity), assay format (HTS, dose-response, selectivity), target association, assay technology platform (HTRF, AlphaScreen, SPR, NMR), assay validation status, GLP compliance flag, detection method, assay protocol reference, throughput capacity, and responsible scientist. Sourced from IDBS/Dotmatics ELN.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`hts_campaign` (
    `hts_campaign_id` BIGINT COMMENT 'Unique surrogate identifier for the HTS campaign record in the discovery data product. Primary key for all downstream joins and lineage tracking.',
    `assay_id` BIGINT COMMENT 'Foreign key linking to discovery.assay. Business justification: HTS campaigns execute screening using specific assays. The campaign currently has assay_format, assay_technology, target_name, target_class as denormalized attributes. Adding assay_id FK establishes t',
    `compound_library_id` BIGINT COMMENT 'Reference to the compound library screened in this campaign, linking to the compound library master record that defines the collection of molecules tested (e.g., diversity set, focused kinase library, natural product library).',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: HTS campaigns are major cost events requiring cost center allocation for financial tracking, budget management, and project costing. Enables campaign cost analysis, resource planning, and financial re',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: HTS campaigns are cost-tracked R&D projects requiring internal order assignment for budget control, variance analysis, and cost-per-screen metrics essential to pharmaceutical screening operations and ',
    `invention_disclosure_id` BIGINT COMMENT 'Foreign key linking to intellectual.invention_disclosure. Business justification: HTS campaigns identify novel hits requiring invention disclosure; direct linkage ensures IP capture from screening, tracks disclosure-to-filing pipeline, and supports patent prosecution strategy for s',
    `employee_id` BIGINT COMMENT 'FK to workforce.employee',
    `primary_hts_employee_id` BIGINT COMMENT 'Reference to the scientist or principal investigator responsible for the HTS campaign. Accountable for campaign design, execution quality, and data integrity. Maps to the employee/researcher master record.',
    `program_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_program. Business justification: HTS campaigns operate under compliance programs governing data integrity, GLP compliance, and electronic records management. Program assignment determines audit scope, inspection readiness requirement',
    `project_id` BIGINT COMMENT 'Reference to the parent drug discovery project under which this HTS campaign is executed. Links the campaign to the broader target identification and hit-to-lead program for portfolio tracking.',
    `actual_end_date` DATE COMMENT 'Date on which the HTS campaign screening execution was completed. Used to calculate campaign duration, throughput metrics, and to trigger downstream hit confirmation workflows.',
    `actual_start_date` DATE COMMENT 'Date on which the HTS campaign screening execution actually commenced. Compared against planned_start_date to measure schedule variance and operational efficiency.',
    `assay_format` STRING COMMENT 'Scientific format of the assay used in the campaign, indicating whether the screen measures biochemical activity (purified protein), cellular response, whole-organism phenotype, direct binding (biophysical), or fragment-based interactions. Critical for interpreting hit quality and SAR analysis.. Valid values are `biochemical|cell_based|phenotypic|biophysical|fragment_based`',
    `assay_technology` STRING COMMENT 'Specific detection technology or instrumentation platform used in the assay (e.g., HTRF, AlphaScreen, FRET, TR-FRET, FP, luminescence, absorbance, imaging). Determines data interpretation rules and quality thresholds. [ENUM-REF-CANDIDATE: HTRF|AlphaScreen|FRET|TR-FRET|FP|luminescence|absorbance|imaging|SPR|ITC — promote to reference product]',
    `campaign_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the HTS campaign, assigned by the ELN or LIMS system (e.g., HTS-EGFR-2024). Used for cross-system referencing in Dotmatics, LabWare, and project management tools.. Valid values are `^HTS-[A-Z0-9]{4,12}-[0-9]{4}$`',
    `campaign_description` STRING COMMENT 'Free-text scientific description of the HTS campaign objectives, biological rationale, assay design, and any special conditions or deviations from standard protocols. Provides context for data interpretation and scientific review.',
    `campaign_name` STRING COMMENT 'Human-readable descriptive name of the HTS campaign, typically including the target name and campaign purpose (e.g., EGFR Kinase Primary Screen Q1 2024). Used in reports, dashboards, and scientific communications.',
    `campaign_status` STRING COMMENT 'Current lifecycle state of the HTS campaign, tracking progression from planning through execution to completion or cancellation. Drives operational dashboards and resource allocation decisions.. Valid values are `planned|in_progress|completed|on_hold|cancelled`',
    `coefficient_of_variation_percent` DECIMAL(18,2) COMMENT 'Percentage coefficient of variation of the neutral control wells across all campaign plates, measuring intra- and inter-plate reproducibility. Acceptable CV% thresholds are defined per assay type and are a key quality acceptance criterion.',
    `compounds_screened_count` STRING COMMENT 'Total number of unique compounds tested in this HTS campaign. Key operational metric for campaign scope, resource planning, and hit rate denominator calculation.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the HTS campaign record was first created in the system. Supports audit trail requirements under 21 CFR Part 11 and GLP data integrity regulations.',
    `cro_involved` BOOLEAN COMMENT 'Indicates whether a Contract Research Organization (CRO) was engaged to execute or support this HTS campaign. Drives vendor management, data transfer agreement requirements, and IP ownership tracking.',
    `cro_name` STRING COMMENT 'Name of the CRO engaged for this HTS campaign, when cro_involved is True. Used for vendor performance tracking, contract management, and regulatory audit trail.',
    `data_quality_flag` STRING COMMENT 'Overall data quality assessment for the HTS campaign based on Z factor, CV%, plate failure rate, and control performance. Determines whether campaign data is accepted for hit identification and downstream SAR analysis.. Valid values are `pass|fail|under_review|conditional_pass`',
    `eln_notebook_reference` STRING COMMENT 'Reference identifier linking this HTS campaign to the corresponding experiment record in the Electronic Lab Notebook (ELN) system (IDBS E-WorkBook or Dotmatics). Provides traceability to raw experimental data, protocols, and scientist sign-off records.',
    `failed_plate_count` STRING COMMENT 'Number of assay plates that failed quality control criteria and were excluded from hit identification analysis. High failed plate counts may trigger campaign re-screening decisions.',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether this HTS campaign was conducted under Good Laboratory Practice (GLP) regulations. GLP compliance is required for studies intended to support regulatory submissions (IND/NDA). Non-GLP campaigns are exploratory research.',
    `hit_count` STRING COMMENT 'Number of compounds that met or exceeded the hit threshold criteria in this campaign. Used to calculate hit rate and to scope confirmatory screening workload.',
    `hit_rate_percent` DECIMAL(18,2) COMMENT 'Percentage of screened compounds that qualified as hits (hit_count / compounds_screened_count × 100). Key campaign quality metric used to assess assay selectivity, library quality, and target druggability. Stored as a raw business measurement, not a derived KPI.',
    `hit_threshold_percent` DECIMAL(18,2) COMMENT 'Percentage inhibition or activation threshold used to define a hit in this campaign (e.g., ≥50% inhibition at screening concentration). Determines the stringency of hit identification and directly impacts hit count and hit rate.',
    `lims_batch_code` STRING COMMENT 'Batch or run identifier assigned by the LIMS (LabWare or Thermo Fisher SampleManager) for the sample processing associated with this HTS campaign. Enables traceability of compound samples, plate preparation, and analytical results.',
    `planned_start_date` DATE COMMENT 'Scheduled start date for the HTS campaign as defined in the project plan. Used for resource scheduling, capacity planning, and tracking schedule adherence.',
    `plate_count` STRING COMMENT 'Total number of assay plates processed during the campaign. Used for capacity planning, reagent consumption tracking, and quality control review scope.',
    `plate_format` STRING COMMENT 'Microplate format used in the HTS campaign, defining the number of wells per plate. Determines throughput capacity, liquid handling requirements, and data volume per plate.. Valid values are `96_well|384_well|1536_well|3456_well`',
    `positive_control_compound` STRING COMMENT 'Name or identifier of the reference compound used as the positive control in the assay (known active compound). Defines the 100% inhibition/activation benchmark for data normalization and Z factor calculation.',
    `screen_type` STRING COMMENT 'Classification of the screening campaign by its scientific purpose in the HTS funnel. Primary screens test the full compound library; confirmatory screens re-test hits; counter-screens eliminate false positives; dose-response screens establish potency; selectivity screens assess off-target activity.. Valid values are `primary|confirmatory|counter_screen|dose_response|selectivity`',
    `screening_concentration_um` DECIMAL(18,2) COMMENT 'Single-point screening concentration in micromolar (µM) at which compounds are tested in the primary screen. Defines the activity threshold context for hit identification and is a critical parameter for hit rate comparability across campaigns.',
    `signal_to_background_ratio` DECIMAL(18,2) COMMENT 'Ratio of the positive control signal to the background (negative control) signal, measuring the dynamic range of the assay. A higher S/B ratio indicates a more robust assay window. Complementary to Z factor for assay quality assessment.',
    `target_class` STRING COMMENT 'Pharmacological class of the molecular target being screened. Used for portfolio analysis, technology platform selection, and benchmarking hit rates across target families. [ENUM-REF-CANDIDATE: kinase|GPCR|protease|ion_channel|nuclear_receptor|epigenetic|PPI|phosphatase|transporter|other — promote to reference product]',
    `target_name` STRING COMMENT 'Name of the biological target (protein, enzyme, receptor, pathway node) being screened against in this campaign (e.g., EGFR, BRAF V600E, TNF-alpha). Central scientific identifier linking the campaign to the drug discovery target portfolio.',
    `therapeutic_area` STRING COMMENT 'Disease or therapeutic area that the HTS campaign is intended to address (e.g., Oncology, Immunology, Rare Diseases, Neuroscience). Aligns the campaign to the companys R&D portfolio strategy and pipeline reporting. [ENUM-REF-CANDIDATE: oncology|immunology|rare_disease|neuroscience|cardiovascular|infectious_disease|metabolic|respiratory — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the HTS campaign record. Required for data lineage tracking, change control auditing, and Silver layer incremental processing in the Databricks Lakehouse.',
    `z_prime_factor` DECIMAL(18,2) COMMENT 'Statistical measure of assay quality (Z factor) calculated from positive and negative control signals, ranging from 0 to 1. A Z ≥ 0.5 indicates an acceptable HTS assay window. Critical quality gate for campaign data acceptance per SLAS and NIH NCATS standards.',
    CONSTRAINT pk_hts_campaign PRIMARY KEY(`hts_campaign_id`)
) COMMENT 'Master record for High-Throughput Screening (HTS) campaigns executed against compound libraries. Captures campaign name, target or assay being screened, compound library used, screening format (primary, confirmatory, counter-screen), campaign status, start and end dates, number of compounds screened, hit rate, assay window (Z-prime factor), screening technology platform, CRO involvement flag, and campaign owner. Central operational entity for HTS execution tracking.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`screening_result` (
    `screening_result_id` BIGINT COMMENT 'Unique surrogate identifier for each individual screening result record in the HTS or dose-response assay campaign. Primary key for the screening_result data product in the discovery domain.',
    `assay_id` BIGINT COMMENT 'Reference to the assay definition used to generate this screening result, including assay type, target, and protocol version.',
    `employee_id` BIGINT COMMENT 'Reference to the scientist or analyst responsible for executing or approving this assay run. Required for GLP audit trail and 21 CFR Part 11 electronic signature compliance.',
    `hts_campaign_id` BIGINT COMMENT 'Reference to the High-Throughput Screening (HTS) campaign or screening project under which this result was generated. Enables grouping of results by campaign for SAR analysis.',
    `molecular_target_id` BIGINT COMMENT 'Reference to the biological molecular target (e.g., protein, enzyme, receptor) against which the compound was screened. Central to target identification and MOA studies.',
    `compound_id` BIGINT COMMENT 'Reference to the compound (NCE or NBE) that was screened in this assay run. Links to the compound master record in the compound library.',
    `coefficient_of_variation_pct` DECIMAL(18,2) COMMENT 'Coefficient of variation (CV%) for replicate measurements of this compound in the assay run. Measures intra-assay reproducibility; high CV% triggers data quality review.',
    `compound_concentration_um` DECIMAL(18,2) COMMENT 'Concentration of the compound tested in the assay well, expressed in micromolar (µM). Critical for dose-response curve fitting and potency determination.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this screening result record was first created in the system. Required for GLP audit trail and 21 CFR Part 11 electronic record compliance.',
    `curve_fit_r_squared` DECIMAL(18,2) COMMENT 'Coefficient of determination (R²) from the dose-response curve fitting model. Values close to 1.0 indicate a high-quality fit. Used as a data quality gate for potency value acceptance.',
    `data_quality_flag` STRING COMMENT 'Data quality status assigned to this screening result based on automated QC rules and manual review. flagged indicates a potential issue requiring review; rejected excludes the result from downstream analysis.. Valid values are `valid|flagged|rejected|under_review`',
    `ec50_nm` DECIMAL(18,2) COMMENT 'Half-maximal effective concentration (EC50) derived from dose-response curve fitting, expressed in nanomolar (nM). Key potency metric for agonist/activator compounds.',
    `eln_notebook_ref` STRING COMMENT 'Reference identifier linking this screening result to the corresponding experiment entry in the Electronic Lab Notebook (ELN) system (IDBS E-WorkBook or Dotmatics). Provides traceability to the original experimental record.',
    `hill_slope` DECIMAL(18,2) COMMENT 'Hill slope (cooperativity coefficient) from the four-parameter logistic (4PL) dose-response curve fit. Values near 1 indicate simple binding; values significantly different from 1 may indicate cooperativity, aggregation, or assay artifacts.',
    `ic50_nm` DECIMAL(18,2) COMMENT 'Half-maximal inhibitory concentration (IC50) derived from dose-response curve fitting, expressed in nanomolar (nM). Key potency metric for inhibitory compounds in SAR analysis and hit-to-lead progression.',
    `instrument_code` STRING COMMENT 'Identifier of the laboratory instrument (e.g., plate reader, liquid handler, mass spectrometer) used to generate the raw signal. Supports instrument qualification tracking and systematic error investigation per GLP.',
    `is_hit_to_lead_eligible` BOOLEAN COMMENT 'Boolean flag indicating whether this compound result meets the predefined criteria for progression into the hit-to-lead (H2L) phase, based on potency, selectivity, and data quality thresholds.',
    `ki_nm` DECIMAL(18,2) COMMENT 'Inhibition constant (Ki) representing the binding affinity of the compound to the target, expressed in nanomolar (nM). Derived from competitive binding or enzyme kinetics assays. Used in mechanistic SAR studies.',
    `lims_result_ref` STRING COMMENT 'Reference identifier from the Laboratory Information Management System (LIMS) for this screening result record. Enables bidirectional traceability between the lakehouse silver layer and the operational LIMS source system.',
    `max_response_percent` DECIMAL(18,2) COMMENT 'Maximum observed response (top asymptote) from the dose-response curve, expressed as a percentage of control. Indicates the efficacy ceiling of the compound at the target.',
    `min_response_percent` DECIMAL(18,2) COMMENT 'Minimum observed response (bottom asymptote) from the dose-response curve, expressed as a percentage of control. Used to assess baseline signal and curve quality.',
    `pan_assay_interference_flag` BOOLEAN COMMENT 'Boolean flag indicating whether the compound has been identified as a Pan-Assay Interference Compound (PAINS) — a compound that produces artifactual activity signals across multiple assays due to non-specific mechanisms. PAINS compounds are deprioritized in hit-to-lead.',
    `percent_activation` DECIMAL(18,2) COMMENT 'Calculated percentage activation of the target relative to controls. Primary activity metric for agonist/activator HTS campaigns. Null for inhibition assays.',
    `percent_inhibition` DECIMAL(18,2) COMMENT 'Calculated percentage inhibition of the target activity relative to positive and negative controls on the same plate. Primary activity metric for inhibitory HTS campaigns. Null for activation assays.',
    `plate_barcode` STRING COMMENT 'Unique barcode identifier of the physical assay plate on which the compound was tested. Used for traceability back to the physical plate in the LIMS and for QC investigations.',
    `plate_column` STRING COMMENT 'Numeric column designation (1–24) of the well on the assay plate. Used for spatial analysis of plate effects and systematic error detection.',
    `plate_row` STRING COMMENT 'Row designation (A–P) of the well on the assay plate. Used for spatial analysis of plate effects and edge-effect QC.. Valid values are `^[A-P]$`',
    `quality_flag_reason` STRING COMMENT 'Free-text or coded reason explaining why a data quality flag was applied (e.g., edge well effect, reagent lot failure, instrument malfunction, outlier replicate). Required when data_quality_flag is flagged or rejected.',
    `raw_signal_value` DECIMAL(18,2) COMMENT 'Unprocessed instrument signal reading from the assay detector (e.g., fluorescence units, luminescence counts, absorbance). Preserved as the primary measurement for audit and reanalysis.',
    `reagent_lot_number` STRING COMMENT 'Lot identifier of the key assay reagent (e.g., enzyme, antibody, cell line passage) used in this assay run. Enables reagent lot correlation analysis for systematic variability investigation.',
    `replicate_number` STRING COMMENT 'Sequential replicate index for this compound-assay combination within the same run (e.g., 1, 2, 3). Enables statistical aggregation across replicates and assessment of intra-assay variability.',
    `result_classification` STRING COMMENT 'Scientific classification of the screening result based on activity thresholds and confirmatory data. Drives hit-to-lead progression decisions. [ENUM-REF-CANDIDATE: active|inactive|inconclusive|toxic|hit|confirmed_hit|false_positive|pan_assay_interference — promote to reference product]. Valid values are `active|inactive|inconclusive|toxic|confirmed_hit|false_positive`',
    `run_date` DATE COMMENT 'Calendar date on which the assay run was executed. Used for temporal trending, reagent lot correlation, and GLP audit trail compliance.',
    `run_timestamp` TIMESTAMP COMMENT 'Precise date and time when the assay instrument reading was captured. Supports intra-day sequencing, instrument log correlation, and 21 CFR Part 11 electronic record compliance.',
    `selectivity_score` DECIMAL(18,2) COMMENT 'Quantitative selectivity score measuring the compounds specificity for the primary target versus off-target activities in a selectivity panel. Higher scores indicate greater selectivity. Used in SAR-driven lead optimization.',
    `signal_to_background_ratio` DECIMAL(18,2) COMMENT 'Ratio of the positive control signal to the background (negative control) signal on the assay plate. A key plate-level QC metric; low S/B ratios indicate assay degradation or reagent failure.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this screening result record. Supports change tracking, audit trail requirements, and incremental data pipeline processing in the Databricks lakehouse.',
    `well_position` STRING COMMENT 'Alphanumeric well position on the assay plate (e.g., A01, H12, P24) indicating the exact location of the compound in the plate layout. Standard SBS/ANSI plate format.. Valid values are `^[A-P]([0-9]|[1-2][0-9])$`',
    `z_prime_factor` DECIMAL(18,2) COMMENT 'Z factor for the assay plate, a dimensionless statistical metric (range -∞ to 1) measuring assay quality based on signal window and variability. Z ≥ 0.5 is the accepted threshold for a valid HTS assay plate.',
    CONSTRAINT pk_screening_result PRIMARY KEY(`screening_result_id`)
) COMMENT 'Transactional record capturing individual compound screening results from HTS campaigns, dose-response assays, and selectivity panels. Captures compound, assay, and campaign references, plate/well position, raw signal, percent inhibition/activation, potency values (IC50/EC50/Ki), Hill slope, curve fit quality (R-squared), result classification (active, inactive, inconclusive, toxic, hit, confirmed hit, false positive), selectivity score, replicate number, run date, and data quality flags. Includes hit-to-lead eligibility determination. Distinct from in_vitro_study: screening_result covers primary and confirmatory screening at scale; in_vitro_study covers deeper mechanistic follow-up on selected compounds.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`sar_study` (
    `sar_study_id` BIGINT COMMENT 'Unique system-generated identifier for the SAR study record. Primary key for this entity.',
    `assay_id` BIGINT COMMENT 'Foreign key linking to discovery.assay. Business justification: SAR (Structure-Activity Relationship) studies use specific assays to measure potency and selectivity of synthesized analogs. The study table currently has assay_type as a denormalized STRING attribute',
    `compound_id` BIGINT COMMENT 'Reference to the single best-performing compound identified from this SAR study, based on the combination of potency, selectivity, and ADME profile. Candidate for progression to the next discovery stage.',
    `hts_campaign_id` BIGINT COMMENT 'Reference to the originating High-Throughput Screening (HTS) campaign from which the hit compounds for this SAR study were identified. Provides lineage from HTS to lead optimization.',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: SAR studies are discrete R&D activities requiring dedicated cost tracking via internal orders for financial planning, cost-per-analog analysis, and stage-gate decision support in medicinal chemistry o',
    `lead_series_id` BIGINT COMMENT 'Reference to the lead chemical series under investigation in this SAR study. Links to the compound series master record in the compound library.',
    `molecular_target_id` BIGINT COMMENT 'Reference to the biological molecular target (e.g., protein, receptor, enzyme) that the SAR study is designed to modulate. Links to the target identification master record.',
    `patent_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent. Business justification: SAR studies generate patentable inventions (novel analogs, structure-activity relationships); patent linkage tracks invention disclosures from medicinal chemistry, supports patent filing decisions, an',
    `employee_id` BIGINT COMMENT 'Reference to the principal medicinal chemist or scientist responsible for designing and executing this SAR study. Used for accountability, expertise tracking, and publication attribution.',
    `project_id` BIGINT COMMENT 'Reference to the parent drug discovery project under which this SAR study is conducted. Enables roll-up reporting at the project level.',
    `sar_director_employee_id` BIGINT COMMENT 'Reference to the study director responsible for the overall scientific and regulatory conduct of the SAR study. Required for GLP-compliant studies per 21 CFR Part 58.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: SAR studies document lead optimization and are included in Module 3.2.S (drug substance chemistry). Real regulatory requirement: structure-activity relationship data supports impurity qualification an',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: SAR studies may involve outsourced analog synthesis or specialized assay services from CRO vendors. Procurement manages vendor qualification, quality agreements, IP protection, and service delivery—co',
    `actual_completion_date` DATE COMMENT 'Date on which the SAR study was actually completed and final data locked in the ELN. Compared against target completion date for schedule variance analysis.',
    `adme_impact_summary` STRING COMMENT 'Narrative summary of how structural modifications in this SAR study impacted ADME properties including metabolic stability, permeability, solubility, plasma protein binding, and CYP inhibition. Sourced from LIMS and ELN data.',
    `analogs_synthesized_count` STRING COMMENT 'Total count of chemical analogs synthesized and tested within this SAR study. Key productivity metric for medicinal chemistry resource planning and portfolio reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this SAR study record was first created in the data platform. Used for audit trail, data lineage, and compliance with 21 CFR Part 11 electronic records requirements.',
    `data_quality_score` DECIMAL(18,2) COMMENT 'Numeric score (0–100) reflecting the completeness and reliability of the experimental data captured in this SAR study, based on assay reproducibility, data completeness, and ELN audit trail integrity. Used for data governance and AI/ML model training quality gates.',
    `eln_notebook_reference` STRING COMMENT 'Reference identifier or URL to the corresponding study record in the IDBS E-WorkBook or Dotmatics Electronic Lab Notebook (ELN). Provides traceability to the primary research data source.',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether this SAR study was conducted under Good Laboratory Practice (GLP) regulations. True = GLP-compliant study; False = non-GLP exploratory research. Relevant for regulatory submission packages.',
    `indication` STRING COMMENT 'Specific disease or medical condition that the compounds in this SAR study are intended to treat or prevent (e.g., Non-Small Cell Lung Cancer, Rheumatoid Arthritis). More granular than therapeutic area.',
    `key_structural_features` STRING COMMENT 'Free-text or structured description of the key chemical structural features (pharmacophores, functional groups, scaffolds, substituents) analyzed in this SAR study to drive potency, selectivity, or ADME properties.',
    `mechanism_of_action` STRING COMMENT 'Description of the biochemical mechanism by which the compounds in this series exert their pharmacological effect on the target (e.g., competitive inhibition, allosteric modulation, covalent binding).',
    `metabolic_stability_flag` BOOLEAN COMMENT 'Indicates whether the lead compounds in this SAR study met the predefined metabolic stability criteria (e.g., microsomal half-life threshold). True = criteria met; False = criteria not met.',
    `nce_nbe_type` STRING COMMENT 'Classification of the compound series as a New Chemical Entity (NCE, small molecule) or New Biological Entity (NBE, biologic/large molecule) or hybrid. Determines regulatory pathway and IP strategy.. Valid values are `NCE|NBE|hybrid`',
    `patent_filing_flag` BOOLEAN COMMENT 'Indicates whether a patent application has been initiated for compounds or methods arising from this SAR study. True = patent filing in progress or completed; False = no patent action taken.',
    `permeability_flag` BOOLEAN COMMENT 'Indicates whether the lead compounds demonstrated acceptable membrane permeability (e.g., Caco-2 or PAMPA assay thresholds). True = acceptable permeability achieved; False = not achieved.',
    `potency_metric_type` STRING COMMENT 'Type of biochemical potency measurement used to characterize compound activity in this SAR study (e.g., IC50 for inhibitory concentration, Ki for inhibition constant, EC50 for effective concentration).. Valid values are `IC50|Ki|EC50|Kd|pIC50|pKi`',
    `potency_range_max_nm` DECIMAL(18,2) COMMENT 'Highest (least potent) IC50 or Ki value observed across all analogs in this SAR study, expressed in nanomolar (nM). Together with the minimum, defines the potency range of the series.',
    `potency_range_min_nm` DECIMAL(18,2) COMMENT 'Lowest (most potent) IC50 or Ki value observed across all analogs in this SAR study, expressed in nanomolar (nM). Represents the best-in-series potency achieved.',
    `progression_decision` STRING COMMENT 'Outcome decision made at the conclusion of the SAR study regarding whether the lead series should progress to the next stage of drug discovery (e.g., lead optimization, candidate selection) or be deprioritized.. Valid values are `progress|deprioritize|terminate|on_hold|pending_review`',
    `sar_hypothesis` STRING COMMENT 'Scientific hypothesis describing the proposed relationship between structural features of the compound series and the observed or expected biological activity. Captured from the ELN study plan.',
    `selectivity_findings` STRING COMMENT 'Summary of selectivity data for the lead compounds against off-target proteins or related family members. Describes selectivity ratios, panel screening results, and any observed off-target liabilities.',
    `selectivity_ratio` DECIMAL(18,2) COMMENT 'Quantitative ratio of the compounds potency against the primary target versus the most relevant off-target (e.g., 100-fold selective over related kinase). Key metric for candidate progression decisions.',
    `start_date` DATE COMMENT 'Date on which the SAR study was formally initiated, corresponding to the first experimental activity recorded in the ELN. Used for timeline tracking and portfolio planning.',
    `study_name` STRING COMMENT 'Descriptive title of the SAR study, typically including the lead series name and therapeutic target (e.g., Series-7 EGFR Kinase Inhibitor Optimization). Used for display and search in ELN and project management tools.',
    `study_number` STRING COMMENT 'Externally-known, human-readable unique identifier assigned to the SAR study at initiation (e.g., SAR-ONC-202401). Used for cross-system referencing in ELN, LIMS, and project tracking systems.. Valid values are `^SAR-[A-Z0-9]{2,10}-[0-9]{4,6}$`',
    `study_phase` STRING COMMENT 'Stage of the drug discovery funnel at which this SAR study is conducted. Aligns with the hit-to-lead and lead optimization progression framework used in medicinal chemistry.. Valid values are `hit_identification|hit_to_lead|lead_optimization|candidate_selection`',
    `study_report_reference` STRING COMMENT 'Document identifier or Veeva Vault reference for the formal SAR study report summarizing findings, conclusions, and progression recommendations. Provides traceability to the official scientific record.',
    `study_status` STRING COMMENT 'Current lifecycle state of the SAR study. Drives workflow routing and portfolio reporting. terminated indicates early discontinuation; archived indicates data locked in ELN.. Valid values are `planned|active|on_hold|completed|terminated|archived`',
    `target_completion_date` DATE COMMENT 'Planned date by which the SAR study is expected to be completed and key findings reported. Used for project milestone tracking and resource scheduling.',
    `therapeutic_area` STRING COMMENT 'Broad disease area or therapeutic category targeted by the SAR study (e.g., Oncology, Immunology, Rare Diseases). Used for portfolio segmentation and resource allocation. [ENUM-REF-CANDIDATE: oncology|immunology|rare_diseases|neuroscience|cardiovascular|infectious_disease|metabolic — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this SAR study record. Supports audit trail requirements and change tracking per 21 CFR Part 11 and ALCOA+ data integrity principles.',
    CONSTRAINT pk_sar_study PRIMARY KEY(`sar_study_id`)
) COMMENT 'Master record for Structure-Activity Relationship (SAR) studies conducted to understand how structural modifications to a compound affect its biological activity. Captures study name, lead series identifier, target identifier, SAR hypothesis, key structural features analyzed, number of analogs synthesized, potency range observed, selectivity findings, ADME impact, study status, lead scientist, and ELN notebook reference from IDBS/Dotmatics. Core entity for medicinal chemistry optimization.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`lead_series` (
    `lead_series_id` BIGINT COMMENT 'Unique system-generated identifier for the lead series record. Primary key for the lead_series data product in the discovery domain.',
    `compound_id` BIGINT COMMENT 'Reference to the compound record representing the best-performing compound within this lead series at the current stage, used as the benchmark for potency, selectivity, and ADME profiling comparisons.',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: SAR-to-market traceability: connects lead optimization series to commercial formulation for regulatory CMC narratives, development history documentation, and IP prosecution support. Essential for CMC ',
    `employee_id` BIGINT COMMENT 'Reference to the lead medicinal chemist or scientist who originated and is responsible for the lead series. Used for accountability, knowledge management, and ELN traceability.',
    `hts_campaign_id` BIGINT COMMENT 'Reference to the originating High-Throughput Screening (HTS) campaign from which the initial hits in this series were identified. Provides traceability from lead series back to the screening event.',
    `invention_disclosure_id` BIGINT COMMENT 'Foreign key linking to intellectual.invention_disclosure. Business justification: Lead series generate invention disclosures for novel scaffolds and SAR; disclosure linkage tracks IP capture from medicinal chemistry, supports patent filing decisions, and documents innovation pipeli',
    `licensing_agreement_id` BIGINT COMMENT 'Foreign key linking to intellectual.licensing_agreement. Business justification: Lead series may be in-licensed or out-licensed; agreement linkage tracks licensed rights, royalty obligations, milestone payments, territory restrictions, and field-of-use limitations for portfolio ma',
    `molecular_target_id` BIGINT COMMENT 'Reference to the primary molecular target (e.g., protein, enzyme, receptor) against which this lead series is designed to act. Central to target-based drug discovery and SAR analysis.',
    `patent_family_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_family. Business justification: Lead series represent patentable chemical scaffolds; patent family linkage tracks composition-of-matter protection, supports stage gate IP assessments, and enables portfolio prioritization based on IP',
    `project_id` BIGINT COMMENT 'Foreign key linking to discovery.discovery_project. Business justification: Lead series are chemical series progressing through hit-to-lead and lead optimization stages within discovery projects. The series table currently has program_code as a denormalized STRING attribute. ',
    `adme_profile_summary` STRING COMMENT 'Summary of the Absorption, Distribution, Metabolism, and Excretion (ADME) profile for the lead series, including key in vitro ADME data such as microsomal stability, permeability (Caco-2/PAMPA), plasma protein binding, and CYP inhibition flags.',
    `compound_count` STRING COMMENT 'Total number of discrete compounds synthesized and registered within this lead series. Indicates the breadth of SAR exploration and medicinal chemistry effort invested in the series.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this lead series record was first created in the system. Supports audit trail, data lineage, and GLP/21 CFR Part 11 electronic records compliance.',
    `current_stage` STRING COMMENT 'Current stage of the lead series within the drug discovery pipeline, from hit confirmation through candidate nomination. Distinct from series_status in that it reflects the scientific progression stage rather than the governance lifecycle state.. Valid values are `hit_confirmation|hit_to_lead|lead_optimization|candidate_nomination`',
    `deprioritization_date` DATE COMMENT 'Date on which the lead series was formally deprioritized or stopped. Null if the series is still active. Used for portfolio analytics and resource reallocation tracking.',
    `drug_likeness_score` DECIMAL(18,2) COMMENT 'Composite drug-likeness score for the best-in-class compound in the series, typically based on Lipinski Rule of Five parameters or QED (Quantitative Estimate of Drug-likeness). Ranges from 0 to 1; higher values indicate better drug-likeness.',
    `eln_notebook_reference` STRING COMMENT 'Reference identifier linking this lead series to the primary Electronic Lab Notebook (ELN) experiment or project in IDBS E-WorkBook or Dotmatics where the originating research data is recorded. Ensures data traceability and GLP audit trail.',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether the key studies supporting this lead series have been conducted under Good Laboratory Practice (GLP) conditions as required for regulatory submission. True = GLP-compliant studies on record.',
    `indication` STRING COMMENT 'Specific disease indication or clinical condition that the lead series is intended to treat or prevent (e.g., Non-Small Cell Lung Cancer, Rheumatoid Arthritis). Aligns with the therapeutic area and drives clinical development planning.',
    `ip_landscape_assessment` STRING COMMENT 'Narrative assessment of the Intellectual Property (IP) landscape for the lead series, including freedom-to-operate (FTO) status, known competitor patents covering the scaffold, and patentability assessment. Classified as confidential due to competitive sensitivity.',
    `ip_status` STRING COMMENT 'Current IP status of the lead series scaffold, indicating whether freedom-to-operate has been established, patents have been filed, or IP encumbrances exist. Classified as confidential.. Valid values are `clear|encumbered|under_review|patent_filed|licensed`',
    `moa_description` STRING COMMENT 'Description of the Mechanism of Action (MOA) for the lead series, explaining how compounds in the series interact with the molecular target to produce the desired pharmacological effect.',
    `modality` STRING COMMENT 'Drug modality classification for the lead series, indicating the type of therapeutic molecule (e.g., small molecule, biologic, peptide). Drives CMC strategy, manufacturing approach, and regulatory pathway selection. [ENUM-REF-CANDIDATE: small_molecule|biologic|peptide|oligonucleotide|cell_therapy|gene_therapy|antibody_drug_conjugate|radioligand — promote to reference product]. Valid values are `small_molecule|biologic|peptide|oligonucleotide|cell_therapy|gene_therapy`',
    `molecular_weight_da` DECIMAL(18,2) COMMENT 'Molecular weight of the core scaffold or best-in-class compound in Daltons (Da). Key physicochemical property used in drug-likeness assessment (Lipinski Rule of Five: MW ≤ 500 Da for oral drugs).',
    `nce_nbe_classification` STRING COMMENT 'Classification of the lead series as a New Chemical Entity (NCE), New Biological Entity (NBE), or New Molecular Entity (NME). Determines regulatory pathway, IP strategy, and data exclusivity eligibility.. Valid values are `NCE|NBE|NME`',
    `nomination_date` DATE COMMENT 'Date on which the lead series was formally nominated as a development candidate, marking the transition from discovery to preclinical development. Null if the series has not yet been nominated.',
    `oral_bioavailability_pct` DECIMAL(18,2) COMMENT 'Best-in-class oral bioavailability percentage (%F) for the lead series from preclinical in vivo PK studies. Key ADME metric for assessing drug-likeness and oral dosing feasibility.',
    `pk_profile_summary` STRING COMMENT 'Summary of in vivo Pharmacokinetics (PK) data for the lead series, including key parameters such as oral bioavailability (%F), half-life (t½), clearance (CL), and volume of distribution (Vd) from preclinical species studies.',
    `potency_assay_type` STRING COMMENT 'Type of biochemical or cellular assay used to determine the potency benchmark value (e.g., IC50, Ki, EC50, Kd). Provides context for interpreting the potency_benchmark_nm value.. Valid values are `IC50|Ki|EC50|Kd|pIC50`',
    `potency_benchmark_nm` DECIMAL(18,2) COMMENT 'Best-in-class potency value (IC50 or Ki) for the lead series expressed in nanomolar (nM) concentration. Represents the principal quantitative performance metric for the series and is used in stage-gate go/no-go decisions.',
    `safety_flag` BOOLEAN COMMENT 'Indicates whether any significant safety liabilities (e.g., genotoxicity, hERG inhibition, reactive metabolites, phototoxicity) have been identified for compounds in this lead series. True = known safety liability requiring mitigation.',
    `safety_liability_notes` STRING COMMENT 'Narrative description of identified safety liabilities for the lead series, including the nature of the liability, affected compounds, and proposed mitigation strategies. Populated when safety_flag is True.',
    `sar_maturity_level` STRING COMMENT 'Qualitative assessment of the maturity of the Structure-Activity Relationship (SAR) understanding for the lead series, from early (limited data) to mature (well-defined SAR with predictive models). Used in stage-gate assessments.. Valid values are `early|developing|established|mature`',
    `scaffold_description` STRING COMMENT 'Textual description of the core chemical scaffold or chemotype defining the lead series, including key structural features relevant to Structure-Activity Relationship (SAR) analysis. Captured from ELN records.',
    `selectivity_profile_summary` STRING COMMENT 'Narrative summary of the selectivity profile for the lead series, describing off-target activity, selectivity ratios against related targets, and any known liabilities identified through selectivity panels (e.g., kinase selectivity panel, GPCR panel).',
    `series_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the lead series within the compound governance system (e.g., ONCO-SER-00042). Used as the business identifier across ELN, LIMS, and medicinal chemistry platforms.. Valid values are `^[A-Z]{2,6}-SER-[0-9]{4,8}$`',
    `series_name` STRING COMMENT 'Human-readable name assigned to the lead series, typically reflecting the chemotype or scaffold class (e.g., Pyrimidine Kinase Inhibitor Series A). Used in medicinal chemistry reports and stage-gate presentations.',
    `series_start_date` DATE COMMENT 'Date on which the lead series was formally initiated following hit confirmation from the originating HTS campaign. Marks the beginning of the hit-to-lead phase and is used for timeline and cycle-time analytics.',
    `series_status` STRING COMMENT 'Current lifecycle status of the lead series within the drug discovery pipeline. Governs stage-gate decisions and resource allocation. Values: hit_to_lead (active hit confirmation and early profiling), lead_optimization (active medicinal chemistry optimization), deprioritized (paused or stopped), nominated (candidate nominated for development), on_hold (temporarily paused pending decision).. Valid values are `hit_to_lead|lead_optimization|deprioritized|nominated|on_hold`',
    `smiles_scaffold` STRING COMMENT 'Simplified Molecular Input Line Entry System (SMILES) string representing the core scaffold structure of the lead series. Enables cheminformatics analysis, substructure searching, and computational chemistry workflows.',
    `stage_gate_date` DATE COMMENT 'Date on which the most recent stage-gate committee decision was made for this lead series. Used for tracking progression timelines and portfolio reporting.',
    `stage_gate_decision` STRING COMMENT 'Most recent stage-gate committee decision for the lead series, indicating whether the series has been approved to progress (go), stopped (no_go), placed on hold, or conditionally approved pending specific criteria.. Valid values are `go|no_go|hold|conditional_go`',
    `stage_gate_rationale` STRING COMMENT 'Documented rationale for the most recent stage-gate decision, capturing the scientific, strategic, and risk-based reasoning of the decision committee. Supports audit trail and portfolio governance.',
    `therapeutic_area` STRING COMMENT 'Therapeutic area classification for the lead series, aligning with the companys portfolio strategy (e.g., oncology, immunology, rare disease). Drives resource allocation and stage-gate governance. [ENUM-REF-CANDIDATE: oncology|immunology|rare_disease|neuroscience|cardiovascular|infectious_disease|metabolic|respiratory|hematology|ophthalmology — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this lead series record was last modified. Supports audit trail, change tracking, and 21 CFR Part 11 electronic records compliance.',
    CONSTRAINT pk_lead_series PRIMARY KEY(`lead_series_id`)
) COMMENT 'Master record for chemical lead series progressing through hit-to-lead and lead optimization stages. Captures series name, scaffold/chemotype description, originating HTS campaign, primary target, series status (hit-to-lead, lead optimization, deprioritized, nominated), best-in-class compound identifier, potency benchmark, selectivity profile, ADME profile summary, IP landscape assessment, therapeutic area, program code, and stage-gate progression history with decision rationale. Central entity for tracking medicinal chemistry progression and compound governance decisions from hit confirmation through candidate nomination.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`compound_synthesis` (
    `compound_synthesis_id` BIGINT COMMENT 'Unique surrogate identifier for each compound synthesis record in the discovery domain. Primary key for the compound_synthesis data product. Entity role: TRANSACTION_HEADER — a discrete synthesis event with its own lifecycle, reagents, conditions, and outcomes.',
    `compound_id` BIGINT COMMENT 'Reference to the compound entity that was synthesized in this experiment. Links the synthesis record to the master compound registry (NCE/NBE catalogue).',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: Synthesis activities consume reagents, labor, and equipment charged to cost centers for project costing, resource planning, and financial reporting. Essential for medicinal chemistry budget management',
    `dmf_id` BIGINT COMMENT 'Foreign key linking to regulatory.dmf. Business justification: Synthesis routes and manufacturing processes are documented in Drug Master Files (Type II DMF for API). Real business process: CMC teams reference synthesis data when preparing or updating DMFs for re',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Individual synthesis activities are charged to internal orders for cost-per-compound tracking, essential for portfolio economics, make-vs-buy decisions, and CRO cost benchmarking in pharmaceutical dis',
    `invention_disclosure_id` BIGINT COMMENT 'Foreign key linking to intellectual.invention_disclosure. Business justification: Novel synthetic routes and processes are disclosed as inventions; disclosure linkage tracks process IP, supports patent filing for manufacturing methods, and protects CMC innovations.',
    `lead_series_id` BIGINT COMMENT 'Foreign key linking to discovery.lead_series. Business justification: Compound synthesis efforts by medicinal chemistry teams are organized by lead series. Each synthesis produces an analog within a specific chemical series. The synthesis table currently has series_code',
    `molecular_target_id` BIGINT COMMENT 'Reference to the biological target (protein, enzyme, receptor, or pathway) against which this compound was synthesized. Links synthesis provenance to target identification and MOA studies in the discovery domain.',
    `employee_id` BIGINT COMMENT 'Reference to the medicinal chemist who performed the synthesis. Supports attribution, GLP accountability, and ELN audit trail requirements.',
    `project_id` BIGINT COMMENT 'Reference to the drug discovery project under which this synthesis was conducted. Enables project-level portfolio reporting, resource tracking, and compound series management.',
    `synthesis_route_id` BIGINT COMMENT 'Reference to the defined synthetic route used for this synthesis event. A route captures the ordered sequence of chemical transformations from starting materials to target compound.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Custom synthesis frequently outsourced to CRO/CMO vendors. Procurement manages vendor qualification, quality agreements, IP protection clauses, and service delivery for outsourced synthesis operations',
    `approval_timestamp` TIMESTAMP COMMENT 'Timestamp when the synthesis record received formal electronic approval in the ELN by the supervising scientist. Distinct from record creation; captures the GLP-required second-person review event for data integrity.',
    `batch_number` STRING COMMENT 'Alphanumeric batch identifier assigned to the synthesized compound lot. Used for inventory tracking, biological testing assignment, and downstream traceability through the discovery pipeline. Aligns with SAP MM batch management.. Valid values are `^[A-Z0-9]{4,20}$`',
    `catalyst` STRING COMMENT 'Name and loading of the catalyst or catalytic system used in the reaction (e.g., Pd(PPh3)4, Pd2(dba)3/XPhos, DMAP). Null if the reaction is uncatalysed. Critical for SAR and process chemistry knowledge management.',
    `compound_type` STRING COMMENT 'Classification of the synthesized compound by modality. Distinguishes New Chemical Entities (NCE), New Biological Entities (NBE), peptides, oligonucleotides, PROTACs, fragments, and natural product derivatives. Drives downstream development pathway and regulatory strategy. [ENUM-REF-CANDIDATE: NCE|NBE|peptide|oligonucleotide|PROTAC|fragment|natural_product_derivative — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this synthesis record was first created in the system (ELN or data lakehouse). Mandatory audit field for 21 CFR Part 11 electronic records compliance and GLP data integrity requirements.',
    `eln_experiment_ref` STRING COMMENT 'Unique experiment identifier from the Electronic Lab Notebook system (IDBS E-WorkBook or Dotmatics) that documents the full experimental procedure, observations, and raw data for this synthesis. Provides traceability back to the authoritative source record.',
    `failure_reason` STRING COMMENT 'Free-text description of the reason for synthesis failure or cancellation when synthesis_status is failed or cancelled. Captures root cause information (e.g., no reaction observed, product decomposition, purification failure, starting material unavailable) to support process learning and SAR knowledge management.',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether this synthesis was conducted in full compliance with Good Laboratory Practice (GLP) regulations. GLP-compliant syntheses are required for compounds entering formal preclinical safety studies. True = GLP compliant; False = non-GLP (exploratory research).',
    `hazard_classification` STRING COMMENT 'GHS/CLP hazard classification of the synthesized compound based on its physicochemical and toxicological properties. Governs safe handling, storage, and disposal procedures in the laboratory. [ENUM-REF-CANDIDATE: non_hazardous|flammable|toxic|corrosive|oxidising|highly_toxic|environmental_hazard — promote to reference product]. Valid values are `non_hazardous|flammable|toxic|corrosive|oxidising|highly_toxic`',
    `hplc_purity_percent` DECIMAL(18,2) COMMENT 'Purity of the synthesized compound as determined by High-Performance Liquid Chromatography (HPLC), expressed as area percentage. A Critical Quality Attribute (CQA) for compound registration and screening eligibility. Compounds typically require ≥95% purity for HTS submission.',
    `molecular_formula` STRING COMMENT 'Empirical molecular formula of the synthesized compound (e.g., C18H21N3O2). Derived from structural confirmation data. Used for compound identity verification, registry matching, and regulatory documentation.. Valid values are `^[A-Z][a-z]?[0-9]*([A-Z][a-z]?[0-9]*)*$`',
    `molecular_weight` DECIMAL(18,2) COMMENT 'Calculated molecular weight of the synthesized compound in grams per mole (g/mol), derived from the confirmed chemical structure. Used for stoichiometric calculations, Lipinski rule-of-five assessment, and compound library profiling.',
    `nmr_purity_percent` DECIMAL(18,2) COMMENT 'Purity of the synthesized compound as determined by quantitative Nuclear Magnetic Resonance (NMR) spectroscopy, expressed as percentage. Orthogonal purity assessment to HPLC; used for structural confirmation and identity verification per GLP requirements.',
    `product_mass_mg` DECIMAL(18,2) COMMENT 'Actual mass of isolated compound product in milligrams. Used to determine availability for biological screening, ADME assays, and compound library registration. Directly linked to synthesis scale and yield.',
    `purification_method` STRING COMMENT 'Method used to purify the crude reaction product to achieve the required purity specification (e.g., column chromatography, preparative HPLC, recrystallisation, trituration). Influences final yield and purity outcomes and informs process development decisions.. Valid values are `column_chromatography|preparative_HPLC|recrystallisation|trituration|none|other`',
    `reaction_duration_hours` DECIMAL(18,2) COMMENT 'Total elapsed time of the synthesis reaction in hours. A Critical Process Parameter (CPP) used in reaction optimization and SAR/process correlation studies.',
    `reaction_temperature_c` DECIMAL(18,2) COMMENT 'Temperature at which the synthesis reaction was conducted, expressed in degrees Celsius. A Critical Process Parameter (CPP) that directly influences reaction selectivity, yield, and purity. Captured from ELN experimental conditions.',
    `reagents_description` STRING COMMENT 'Free-text or structured description of the key reagents and their stoichiometric equivalents used in the synthesis (e.g., K2CO3 (2.0 eq), Pd(OAc)2 (5 mol%), SPhos (10 mol%)). Supports reproducibility and GLP documentation requirements.',
    `registered_in_library` BOOLEAN COMMENT 'Indicates whether the synthesized compound has been registered in the corporate compound library for HTS and biological screening. True = registered and available for screening; False = not yet registered or failed registration criteria (e.g., purity < 95%).',
    `smiles_notation` STRING COMMENT 'Canonical SMILES (Simplified Molecular-Input Line-Entry System) string representing the two-dimensional chemical structure of the synthesized compound. Machine-readable format used for cheminformatics, SAR analysis, and compound database registration in Dotmatics.',
    `solvent` STRING COMMENT 'Name of the primary solvent or solvent system used in the synthesis reaction (e.g., DMF, THF, DCM, EtOH, water). Influences reaction kinetics, selectivity, and downstream purification strategy. Relevant to ICH Q3C solvent classification for later-stage development.',
    `storage_condition` STRING COMMENT 'Required storage condition for the synthesized compound to maintain stability and integrity (e.g., room temperature, 2–8°C, −20°C, −80°C, nitrogen atmosphere, desiccator). Derived from compound physicochemical properties and stability data.. Valid values are `RT|2-8C|-20C|-80C|N2_atmosphere|desiccator`',
    `storage_location` STRING COMMENT 'Physical storage location of the synthesized compound batch (e.g., freezer ID, rack, position in compound management system). Enables inventory management and sample retrieval for biological testing.',
    `structural_confirmation_method` STRING COMMENT 'Analytical technique(s) used to confirm the chemical structure of the synthesized compound (e.g., 1H-NMR, 13C-NMR, LCMS, HRMS, IR, X-ray crystallography). Structural confirmation is mandatory for compound registration and GLP compliance. [ENUM-REF-CANDIDATE: 1H-NMR|13C-NMR|LCMS|HRMS|IR|X-ray|multiple — 7 candidates stripped; promote to reference product]',
    `synthesis_date` DATE COMMENT 'Calendar date on which the synthesis reaction was initiated. Principal business event date for this transaction record. Used for timeline tracking, GLP compliance dating, and SAR trend analysis.',
    `synthesis_number` STRING COMMENT 'Human-readable, externally-known business identifier for this synthesis event, typically assigned by the ELN (IDBS E-WorkBook or Dotmatics). Follows site-specific numbering conventions (e.g., MED-SYN-000123). Used for cross-referencing in lab notebooks, SAR databases, and regulatory submissions.. Valid values are `^[A-Z]{2,6}-SYN-[0-9]{6,10}$`',
    `synthesis_purpose` STRING COMMENT 'Scientific purpose for which this compound was synthesized. Classifies the synthesis within the drug discovery workflow (e.g., hit confirmation from HTS, lead optimisation, SAR exploration, ADME probe, tool compound, library synthesis). Enables portfolio analytics and resource allocation reporting.. Valid values are `hit_confirmation|lead_optimisation|SAR_exploration|ADME_probe|tool_compound|library_synthesis`',
    `synthesis_scale_mmol` DECIMAL(18,2) COMMENT 'Molar scale of the synthesis reaction expressed in millimoles (mmol). Determines reagent quantities, expected yield mass, and suitability for downstream biological screening (e.g., HTS vs. focused assay).',
    `synthesis_status` STRING COMMENT 'Current lifecycle state of the synthesis experiment. Tracks progression from planned through execution to completion or failure. Drives workflow routing in the medicinal chemistry pipeline.. Valid values are `planned|in_progress|completed|failed|cancelled`',
    `synthetic_method` STRING COMMENT 'Name or classification of the synthetic methodology applied (e.g., Suzuki coupling, reductive amination, Buchwald-Hartwig amination, solid-phase synthesis). Enables SAR analysis by correlating method with yield and purity outcomes.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this synthesis record. Required for 21 CFR Part 11 audit trail compliance and data integrity monitoring in GLP environments.',
    `yield_percent` DECIMAL(18,2) COMMENT 'Isolated yield of the target compound expressed as a percentage of the theoretical maximum based on the limiting reagent. A primary quantitative outcome metric for synthesis efficiency and SAR optimization. Range: 0.00–100.00.',
    CONSTRAINT pk_compound_synthesis PRIMARY KEY(`compound_synthesis_id`)
) COMMENT 'Transactional record capturing the synthesis of individual compounds by medicinal chemistry teams. Captures compound identifier, synthesis route identifier, synthetic method, reagents used, reaction conditions (temperature, solvent, catalyst), yield percentage, purity by HPLC/NMR, batch number, synthesis date, synthesizing chemist, ELN experiment reference from IDBS/Dotmatics, and GLP compliance flag. Tracks the manufacturing provenance of discovery compounds.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`adme_profile` (
    `adme_profile_id` BIGINT COMMENT 'Unique surrogate identifier for each ADME profiling record in the discovery domain. Primary key for the adme_profile data product. Entity role: TRANSACTION_HEADER — captures a discrete ADME assay event with its own lifecycle and results.',
    `assay_panel_id` BIGINT COMMENT 'Reference to the standardized ADME assay panel applied during this profiling run, defining the battery of tests performed (e.g., Tier 1 ADME screen, full ADME panel).',
    `compound_id` BIGINT COMMENT 'Reference to the compound under ADME evaluation, linking to the compound master record in the discovery compound library. Satisfies TRANSACTION_HEADER PARTY_REFERENCE category (compound is the principal resource being profiled).',
    `employee_id` BIGINT COMMENT 'Reference to the ADME scientist responsible for executing and reviewing this profiling run. Satisfies TRANSACTION_HEADER PARTY_REFERENCE category for the responsible scientist.',
    `project_id` BIGINT COMMENT 'Reference to the drug discovery project under which this ADME profiling was conducted, enabling project-level aggregation of ADME data for compound progression decisions.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: ADME data is required in Module 4.2.2 (pharmacokinetics) of regulatory submissions. Real regulatory requirement: nonclinical PK/ADME studies must be submitted with traceable study reports. Critical fo',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: ADME profiling frequently outsourced to specialized CRO vendors for permeability, metabolism, protein binding, and PK studies. Vendor qualification, quality agreements, GLP compliance, and data qualit',
    `adme_risk_score` DECIMAL(18,2) COMMENT 'Composite numerical risk score (e.g., 0–100) summarizing overall ADME liability across solubility, permeability, metabolic stability, and DDI risk dimensions. Used for compound ranking and portfolio prioritization in discovery.',
    `assay_concentration_um` DECIMAL(18,2) COMMENT 'Concentration of the compound used in the ADME assay incubation, expressed in micromolar (µM). Required for result interpretation and inter-assay comparability; standard concentrations are typically 1–10 µM.',
    `assay_date` DATE COMMENT 'Calendar date on which the ADME assay panel was executed in the laboratory. Satisfies TRANSACTION_HEADER BUSINESS_EVENT_TIMESTAMP category (day-level precision for assay scheduling and trending).',
    `bbb_kp_uu` DECIMAL(18,2) COMMENT 'Unbound brain-to-plasma concentration ratio (Kp,uu,brain), the quantitative measure of CNS penetration accounting for plasma protein binding. Values >0.3 indicate meaningful CNS exposure; used in CNS drug discovery programs.',
    `bbb_penetration` BOOLEAN COMMENT 'Indicates whether the compound demonstrates blood-brain barrier penetration based on in vitro BBB assay (e.g., MDCK-MDR1, hCMEC/D3) or in vivo brain-to-plasma ratio. Critical for CNS-targeted and CNS-safety assessments.',
    `bioavailability_pct` DECIMAL(18,2) COMMENT 'Estimated oral bioavailability percentage (%F) derived from permeability, solubility, and metabolic stability data using predictive ADME models. Key compound progression criterion for oral drug candidates.',
    `clearance_ml_min_kg` DECIMAL(18,2) COMMENT 'Predicted in vivo hepatic clearance in mL/min/kg, scaled from in vitro microsomal intrinsic clearance using the well-stirred liver model. Used to estimate dose and dosing interval in early drug discovery.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this ADME profile record was first created in the system. Satisfies TRANSACTION_HEADER RECORD_AUDIT_CREATED category. Supports 21 CFR Part 11 electronic records audit trail.',
    `cyp2c9_inhibition_ic50_um` DECIMAL(18,2) COMMENT 'Half-maximal inhibitory concentration (IC50) for CYP2C9 enzyme inhibition in µM. CYP2C9 metabolizes warfarin and NSAIDs; inhibition is a critical DDI safety signal for regulatory submissions.',
    `cyp2d6_inhibition_ic50_um` DECIMAL(18,2) COMMENT 'Half-maximal inhibitory concentration (IC50) for CYP2D6 enzyme inhibition in µM. CYP2D6 metabolizes ~25% of marketed drugs; inhibition is a major DDI liability assessed by FDA and EMA.',
    `cyp3a4_inhibition_ic50_um` DECIMAL(18,2) COMMENT 'Half-maximal inhibitory concentration (IC50) for CYP3A4 enzyme inhibition in µM. CYP3A4 metabolizes ~50% of marketed drugs; inhibition predicts drug-drug interaction (DDI) liability. Key regulatory safety flag.',
    `cyp_inhibition_flag` BOOLEAN COMMENT 'Composite boolean flag indicating whether the compound exhibits significant CYP inhibition risk (any CYP isoform IC50 below the regulatory concern threshold, typically <10 µM). Used for rapid compound triage and progression gating.',
    `efflux_ratio` DECIMAL(18,2) COMMENT 'Ratio of basolateral-to-apical (B→A) over apical-to-basolateral (A→B) permeability in Caco-2 assay. Values >2 indicate active efflux transport (e.g., P-gp substrate), impacting oral bioavailability and CNS penetration.',
    `eln_notebook_reference` STRING COMMENT 'Reference identifier linking this ADME profile to the corresponding experiment entry in the Electronic Lab Notebook (IDBS E-WorkBook or Dotmatics), providing traceability to raw experimental data and GLP documentation.',
    `half_life_h` DECIMAL(18,2) COMMENT 'Predicted or measured plasma half-life of the compound in hours, derived from in vitro microsomal clearance data using allometric scaling or measured directly in in vivo PK studies. Informs dosing frequency predictions.',
    `hlm_clint_ul_min_mg` DECIMAL(18,2) COMMENT 'Intrinsic metabolic clearance measured in human liver microsomes (HLM), expressed as µL/min/mg protein. Used to predict in vivo hepatic clearance and half-life via well-stirred liver model. Critical for dose prediction.',
    `lims_sample_code` STRING COMMENT 'Sample identifier assigned by the LIMS (LabWare or Thermo Fisher SampleManager) for the compound sample used in this ADME assay. Enables traceability from ADME result back to physical sample chain of custody.',
    `metabolic_stability_class` STRING COMMENT 'Categorical classification of compound metabolic stability based on microsomal half-life thresholds (e.g., low: t½ <30 min, medium: 30–60 min, high: >60 min). Used in compound progression scoring and SAR triage.. Valid values are `low|medium|high`',
    `microsomal_half_life_min` DECIMAL(18,2) COMMENT 'In vitro half-life of the compound in liver microsome incubation (human or rat), expressed in minutes. Derived from substrate depletion kinetics; used to classify metabolic stability as low/medium/high.',
    `notes` STRING COMMENT 'Free-text field for ADME scientist observations, anomalies, assay deviations, or contextual notes relevant to interpreting the ADME profile results. Supports GLP documentation requirements.',
    `permeability_caco2_nm_s` DECIMAL(18,2) COMMENT 'Apparent permeability coefficient (Papp A→B) measured in Caco-2 cell monolayer assay, expressed in nm/s. Predicts intestinal absorption and oral bioavailability. Key ADME parameter for BCS classification.',
    `permeability_pampa_nm_s` DECIMAL(18,2) COMMENT 'Passive transcellular permeability measured by PAMPA assay in nm/s. Complements Caco-2 data by isolating passive diffusion component, informing SAR optimization for membrane permeability.',
    `pgp_substrate` BOOLEAN COMMENT 'Indicates whether the compound is identified as a P-glycoprotein (P-gp / MDR1) efflux transporter substrate based on Caco-2 bidirectional permeability or dedicated P-gp inhibition assay. Impacts CNS penetration and oral bioavailability predictions.',
    `plasma_protein_binding_pct` DECIMAL(18,2) COMMENT 'Percentage of compound bound to plasma proteins (albumin, alpha-1-acid glycoprotein) measured by equilibrium dialysis or ultrafiltration. Determines free fraction available for pharmacological activity and clearance.',
    `ppb_method` STRING COMMENT 'Analytical method used to determine plasma protein binding percentage. Rapid equilibrium dialysis (RED) is the industry standard; method choice affects result interpretation and cross-study comparability.. Valid values are `equilibrium_dialysis|rapid_equilibrium_dialysis|ultrafiltration|ultracentrifugation`',
    `profile_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this ADME profiling run, used in ELN (IDBS/Dotmatics) and LIMS cross-referencing. Satisfies TRANSACTION_HEADER BUSINESS_IDENTIFIER category.. Valid values are `^ADME-[A-Z0-9]{4,12}-[0-9]{4,8}$`',
    `profile_status` STRING COMMENT 'Current workflow state of the ADME profile record from data entry through scientific review and approval. Satisfies TRANSACTION_HEADER LIFECYCLE_STATUS category. [ENUM-REF-CANDIDATE: draft|in_progress|completed|reviewed|approved|invalidated — promote to reference product if additional states are needed]. Valid values are `draft|in_progress|completed|reviewed|approved|invalidated`',
    `progression_recommendation` STRING COMMENT 'Scientific recommendation for compound progression based on the overall ADME profile assessment. Drives hit-to-lead and lead optimization decisions. Assigned by the ADME scientist upon profile review and approval.. Valid values are `progress|optimize|deprioritize|hold|fail`',
    `rlm_clint_ul_min_mg` DECIMAL(18,2) COMMENT 'Intrinsic metabolic clearance measured in rat liver microsomes (RLM), expressed as µL/min/mg protein. Supports cross-species PK scaling and preclinical-to-clinical translation of metabolic stability data.',
    `solubility_method` STRING COMMENT 'Analytical method used to determine aqueous solubility, distinguishing kinetic from thermodynamic measurements which have different interpretive implications for drug development.. Valid values are `kinetic|thermodynamic|nephelometric|HPLC|turbidimetric`',
    `solubility_um` DECIMAL(18,2) COMMENT 'Measured aqueous solubility of the compound in micromolar (µM), typically from kinetic or thermodynamic solubility assay. Critical for assessing oral bioavailability and formulation feasibility. Satisfies TRANSACTION_HEADER QUANTITATIVE_RESULT category.',
    `species` STRING COMMENT 'Biological species from which the biological matrix (microsomes, plasma, cells) was derived for this ADME assay. Enables cross-species PK comparison and allometric scaling for preclinical-to-clinical translation.. Valid values are `human|rat|mouse|dog|monkey|rabbit`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this ADME profile record. Satisfies TRANSACTION_HEADER RECORD_AUDIT_UPDATED category. Supports 21 CFR Part 11 audit trail requirements.',
    `volume_of_distribution_l_kg` DECIMAL(18,2) COMMENT 'Predicted or measured apparent volume of distribution (Vd) in L/kg, reflecting the extent of compound distribution into tissues versus plasma. Informs PK/PD modeling and dose prediction.',
    CONSTRAINT pk_adme_profile PRIMARY KEY(`adme_profile_id`)
) COMMENT 'Transactional record capturing ADME (Absorption, Distribution, Metabolism, Excretion) profiling results for compounds under evaluation. Captures compound identifier, assay panel used, solubility value, permeability (Caco-2/PAMPA), plasma protein binding, microsomal stability (human/rat liver microsomes), CYP inhibition profile, P-glycoprotein substrate flag, blood-brain barrier penetration, half-life, clearance rate, bioavailability estimate, assay date, and ADME scientist. Critical for compound progression decisions.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`project` (
    `project_id` BIGINT COMMENT 'Unique surrogate identifier for the drug discovery research project record in the lakehouse silver layer. Primary key for all downstream joins within the discovery domain.',
    `compound_library_id` BIGINT COMMENT 'Reference to the primary compound library or collection used in HTS (High-Throughput Screening) campaigns for this project. Links to the compound management system for screening deck traceability.',
    `fto_analysis_id` BIGINT COMMENT 'Foreign key linking to intellectual.fto_analysis. Business justification: Discovery projects require FTO clearance at stage gates (target validation, lead optimization, candidate nomination); analysis linkage supports portfolio decisions, risk assessment, and strategic plan',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Project resource planning, performance reviews, succession planning, and portfolio governance require FK to employee. Project leader accountability is critical for stage-gate decisions, budget ownersh',
    `licensing_agreement_id` BIGINT COMMENT 'Foreign key linking to intellectual.licensing_agreement. Business justification: Discovery projects often operate under collaboration or in-licensing agreements; linkage tracks licensed rights, diligence obligations, milestone triggers, and royalty terms for financial planning and',
    `medicinal_product_id` BIGINT COMMENT 'Foreign key linking to product.medicinal_product. Business justification: Portfolio lineage tracking: connects research program to marketed medicine for ROI analysis, pipeline reporting, strategic planning. Essential for investment decisions, productivity metrics, and comme',
    `org_unit_id` BIGINT COMMENT 'Foreign key linking to masterdata.org_unit. Business justification: Discovery projects are owned and managed by specific organizational units for governance, resource allocation, headcount planning, and portfolio management. Essential for matrix reporting and accounta',
    `patent_family_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_family. Business justification: Discovery projects generate patent families as key deliverables; family linkage enables portfolio tracking, R&D-to-IP investment analysis, valuation for M&A, and strategic IP planning at program level',
    `program_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_program. Business justification: Discovery projects operate under compliance programs (GxP, data integrity, Part 11) that govern execution standards, audit scope, and inspection readiness. Program assignment is required for regulator',
    `molecular_target_id` BIGINT COMMENT 'Standardized identifier for the primary biological target (e.g., UniProt accession, HGNC gene symbol) the project is designed to modulate. Central to SAR analysis and MOA documentation in IDBS/Dotmatics ELN.',
    `trademark_id` BIGINT COMMENT 'Foreign key linking to intellectual.trademark. Business justification: Discovery projects plan brand strategy early; trademark linkage tracks naming pipeline, supports trademark clearance searches, coordinates filing with development milestones, and protects future comme',
    `actual_candidate_nomination_date` DATE COMMENT 'Date on which the development candidate was formally nominated and the project transitioned to preclinical development. Nullable until nomination occurs. Used for cycle time analytics and portfolio performance measurement.',
    `atc_code` STRING COMMENT 'WHO ATC classification code assigned to the intended drug product based on its therapeutic target and mechanism. Used for market analysis, competitive intelligence, and regulatory classification.. Valid values are `^[A-Z][0-9]{2}[A-Z]{2}[0-9]{2}$`',
    `collaboration_partner_name` STRING COMMENT 'Name of the primary external collaboration partner (CRO, academic institution, or partner pharma company) if external_collaboration_flag is true. Classified confidential as it reveals strategic partnership information.',
    `collaboration_type` STRING COMMENT 'Classification of the external collaboration arrangement. Determines applicable contractual, IP, and regulatory frameworks governing data sharing and compound rights.. Valid values are `cro|academic|co_development|licensing_in|public_private_partnership`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the discovery project record was first created in the system of record (IDBS/Dotmatics or portfolio management system). Supports audit trail requirements under 21 CFR Part 11 and ALCOA+ data integrity principles. Aligns with RECORD_AUDIT_CREATED canonical category.',
    `disease_indication` STRING COMMENT 'Specific disease or condition the project aims to treat or prevent (e.g., Non-Small Cell Lung Cancer, Rheumatoid Arthritis). Free-text aligned to ICD-10 or MeSH terminology for cross-system interoperability.',
    `eln_project_code` STRING COMMENT 'Reference identifier for this discovery project in the IDBS E-WorkBook or Dotmatics ELN system. Enables traceability from the lakehouse silver layer back to the authoritative source system for raw experimental data.',
    `external_collaboration_flag` BOOLEAN COMMENT 'Indicates whether the project involves external partners such as CROs, academic institutions, or other pharmaceutical companies. Triggers additional data governance, IP agreement, and confidentiality controls.',
    `glp_compliance_flag` BOOLEAN COMMENT 'Indicates whether the projects studies are conducted under GLP regulations as required for regulatory submission. GLP-compliant studies are required for safety data submitted in IND applications.',
    `hts_campaign_count` STRING COMMENT 'Number of HTS campaigns executed under this discovery project. Provides a summary indicator of screening activity volume for portfolio reporting and resource utilization analysis.',
    `icd10_code` STRING COMMENT 'Standardized ICD-10 disease classification code for the primary disease indication. Enables cross-domain linkage to clinical, regulatory, and medical affairs data and supports regulatory submissions.. Valid values are `^[A-Z][0-9]{2}(.[0-9A-Z]{1,4})?$`',
    `ip_strategy_note` STRING COMMENT 'Brief description of the IP strategy for the project, including patentability assessment, freedom-to-operate (FTO) status, and filing intentions. Classified confidential as it contains pre-filing IP strategy.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the discovery project record. Required for data lineage tracking, change control auditing, and incremental ETL processing in the Databricks lakehouse silver layer. Aligns with RECORD_AUDIT_UPDATED canonical category.',
    `moa_description` STRING COMMENT 'Scientific description of the proposed mechanism by which the drug candidate modulates the target to achieve therapeutic effect. Captured from ELN records in IDBS/Dotmatics. Critical for IND and NDA/BLA submissions.',
    `modality` STRING COMMENT 'Type of therapeutic modality being pursued in the project. Determines applicable regulatory pathway (NDA vs BLA), manufacturing approach (CMO vs CDMO), and GLP/GMP requirements. Distinguishes NCE from NBE programs. [ENUM-REF-CANDIDATE: small_molecule|biologic|antibody|cell_therapy|gene_therapy|oligonucleotide|peptide — 7 candidates stripped; promote to reference product]',
    `phase` STRING COMMENT 'Current stage of the drug discovery workflow. Progresses from target identification through candidate nomination, representing the standard industry gate-based progression model. Used for portfolio stage-gate reporting and resource planning.. Valid values are `target_identification|target_validation|hit_identification|hit_to_lead|lead_optimization|candidate_nomination`',
    `portfolio_decision` STRING COMMENT 'Most recent portfolio governance committee decision for the project. Recorded at each stage-gate review and drives resource reallocation and pipeline reporting.. Valid values are `continue|pause|terminate|accelerate|partner|deprioritize`',
    `portfolio_decision_date` DATE COMMENT 'Date of the most recent portfolio governance committee decision. Used for audit trail and decision history tracking in conjunction with portfolio_decision.',
    `project_code` STRING COMMENT 'Externally-known alphanumeric project identifier assigned by the portfolio governance office (e.g., DISC-20240001). Used as the business key across IDBS/Dotmatics ELN, SAP project structures, and regulatory submissions. Aligns with the BUSINESS_IDENTIFIER canonical category.. Valid values are `^[A-Z]{2,6}-[0-9]{4,8}$`',
    `project_name` STRING COMMENT 'Human-readable name of the drug discovery project (e.g., KRAS G12C Inhibitor Program). Classified confidential as it may reveal pipeline strategy prior to public disclosure. Aligns with the IDENTITY_LABEL canonical category.',
    `project_status` STRING COMMENT 'Current lifecycle status of the discovery project as managed in the portfolio governance system. Drives portfolio dashboards and resource allocation decisions. Aligns with the LIFECYCLE_STATUS canonical category.. Valid values are `active|on_hold|terminated|completed|pending_review`',
    `project_type` STRING COMMENT 'Classification of the discovery project by the nature of the entity being developed. NCE (New Chemical Entity) and NBE (New Biological Entity) drive distinct regulatory and IP strategies. Aligns with CLASSIFICATION_OR_TYPE canonical category.. Valid values are `nce|nbe|biosimilar|fixed_dose_combination|new_indication|reformulation`',
    `projected_candidate_nomination_date` DATE COMMENT 'Target date by which a development candidate is expected to be nominated and handed off to preclinical development. Key milestone for pipeline planning, IND filing timelines, and portfolio forecasting.',
    `sap_wbs_element` STRING COMMENT 'SAP Project System WBS element code that maps this discovery project to the financial controlling structure in SAP S/4HANA. Enables cost allocation, budget tracking, and financial reporting at the project level.',
    `sponsor` STRING COMMENT 'Senior executive or therapeutic area head who sponsors and champions the project at the portfolio governance level. Distinct from the project leader who manages day-to-day execution.',
    `start_date` DATE COMMENT 'Official date on which the discovery project was formally initiated and approved by portfolio governance. Used for project duration calculations, milestone tracking, and portfolio timeline reporting.',
    `strategic_priority_tier` STRING COMMENT 'Portfolio governance classification indicating the strategic importance of the project (Tier 1 = highest priority, Tier 3 = exploratory). Drives resource allocation, budget prioritization, and executive reporting. Classified confidential as it reflects pipeline strategy.. Valid values are `tier_1|tier_2|tier_3`',
    `target_organism` STRING COMMENT 'Primary biological system or organism used in discovery assays and preclinical models. Relevant for GLP study design, species selection justification in IND applications, and ADME/PK modeling.. Valid values are `human|mouse|rat|non_human_primate|in_vitro`',
    `termination_reason` STRING COMMENT 'Documented reason for project termination or discontinuation (e.g., safety signal, lack of efficacy, strategic reprioritization, IP conflict). Nullable for active projects. Critical for lessons-learned analysis and portfolio retrospectives. [ENUM-REF-CANDIDATE: safety_signal|lack_of_efficacy|strategic_reprioritization|ip_conflict|resource_constraints|competitive_landscape|regulatory_concern — promote to reference product]',
    `therapeutic_area` STRING COMMENT 'Broad disease area or medical specialty the project targets (e.g., Oncology, Immunology, Rare Diseases, Cardiovascular). Used for portfolio segmentation, budget allocation, and strategic alignment reporting. [ENUM-REF-CANDIDATE: oncology|immunology|rare_diseases|cardiovascular|neuroscience|infectious_disease|metabolic|respiratory — promote to reference product]',
    CONSTRAINT pk_project PRIMARY KEY(`project_id`)
) COMMENT 'Master record for drug discovery research projects organized around one or more therapeutic targets or disease indications. Captures project name, project code, therapeutic area, disease indication (ICD-10/MeSH reference), primary and secondary target identifiers (supporting multi-target programs), project phase (target identification, target validation, hit identification, hit-to-lead, lead optimization, candidate nomination), project status, start date, projected candidate nomination date, project leader, team members, budget allocation, strategic priority tier, external collaboration references, and portfolio governance decisions. Top-level organizational entity for the discovery domain providing project-centric views of all discovery activities.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`target_validation_study` (
    `target_validation_study_id` BIGINT COMMENT 'Unique surrogate identifier for the target validation study record in the discovery domain. Primary key for this entity.',
    `compound_id` BIGINT COMMENT 'Internal compound identifier for the chemical probe used in the validation study (where validation_method = chemical_probe). Links to the compound library registry in Dotmatics.',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Target validation studies are discrete cost centers requiring internal order assignment for R&D cost allocation, therapeutic area P&L reporting, and target prioritization decisions based on validation',
    `molecular_target_id` BIGINT COMMENT 'Reference to the molecular target (gene, protein, pathway node) being validated in this study. Links to the master target registry.',
    `project_id` BIGINT COMMENT 'Foreign key linking to discovery.discovery_project. Business justification: Target validation studies are conducted within discovery projects to validate a molecular targets role in disease and its druggability. The study table currently has program_code as a denormalized ST',
    `employee_id` BIGINT COMMENT 'Reference to the principal scientist responsible for conducting and interpreting the target validation study. Links to the HR/personnel master data.',
    `target_study_director_employee_id` BIGINT COMMENT 'Reference to the GLP Study Director accountable for the overall scientific conduct and regulatory compliance of the study, as required under 21 CFR Part 58.33.',
    `therapeutic_area_id` BIGINT COMMENT 'Reference to the therapeutic area master record under which this target validation study is funded and governed, enabling portfolio-level investment tracking.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Target validation often involves CRO vendors for specialized model systems, disease models, or validation assays. Vendor qualification, quality oversight, GLP compliance, and regulatory submission req',
    `biomarker_hypothesis` STRING COMMENT 'Proposed patient selection or pharmacodynamic biomarker hypothesis arising from the validation study, informing future clinical trial design and companion diagnostic strategy.',
    `cost_center_code` STRING COMMENT 'SAP cost center code to which the study expenses are allocated, enabling financial tracking of discovery investment by organizational unit.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this target validation study record was first created in the data platform, supporting audit trail and data lineage requirements under 21 CFR Part 11.',
    `decision_date` DATE COMMENT 'Date on which the go/no-go investment decision was formally recorded by the portfolio governance committee.',
    `disease_area` STRING COMMENT 'Primary therapeutic area or disease indication for which the target is being validated (e.g., oncology, immunology, rare disease, neurology). Aligns with the companys therapeutic area taxonomy.',
    `disease_indication` STRING COMMENT 'Specific disease or condition for which the targets role is being validated (e.g., non-small cell lung cancer, rheumatoid arthritis, Gaucher disease). More granular than disease_area.',
    `disease_linkage_evidence` STRING COMMENT 'Summary of the genetic, epidemiological, or clinical evidence linking the target to the disease (e.g., GWAS associations, somatic mutation frequency, patient cohort data, biomarker correlations).',
    `druggability_assessment` STRING COMMENT 'Assessment of the targets amenability to small molecule, biologic, or other modality intervention based on structural, biochemical, and computational analysis.. Valid values are `high|medium|low|undetermined`',
    `eln_notebook_reference` STRING COMMENT 'Reference identifier linking this study record to the corresponding experiment entries in the Electronic Lab Notebook (ELN) system (IDBS E-WorkBook or Dotmatics), ensuring data traceability.',
    `endpoint_result_unit` STRING COMMENT 'Unit of measure for the primary endpoint result value (e.g., %, nM, fold-change, mm³). Ensures dimensional correctness for cross-study comparisons.',
    `endpoint_result_value` DECIMAL(18,2) COMMENT 'Quantitative result value for the primary study endpoint (e.g., 85.3 for 85.3% knockdown efficiency). Paired with endpoint_result_unit for dimensional context.',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether the study was conducted in compliance with Good Laboratory Practice (GLP) regulations (21 CFR Part 58 / OECD GLP Principles), relevant for regulatory submission support.',
    `go_no_go_decision` STRING COMMENT 'Portfolio governance decision on whether to proceed with further investment in this target based on the validation study outcome. Drives hit-to-lead progression.. Valid values are `go|no_go|conditional_go|pending_review`',
    `moa_description` STRING COMMENT 'Narrative description of the proposed mechanism of action (MOA) by which modulating the target is expected to produce a therapeutic effect in the disease indication.',
    `model_system_name` STRING COMMENT 'Specific name or designation of the biological model system used (e.g., HeLa, MCF-7, C57BL/6 mouse, HCT116 xenograft). Provides experimental reproducibility context.',
    `model_system_type` STRING COMMENT 'Category of biological model system used in the validation study (e.g., cell line, animal model, patient-derived xenograft, organoid). Determines translational relevance of the findings.. Valid values are `cell_line|animal_model|patient_derived|organoid|primary_culture|ex_vivo_tissue`',
    `patent_relevance_flag` BOOLEAN COMMENT 'Indicates whether the target validation findings have been flagged as potentially patentable or relevant to existing IP filings, triggering IP team review.',
    `primary_endpoint` STRING COMMENT 'The principal measurable endpoint used to assess target validation success (e.g., target knockdown efficiency ≥80%, tumour volume reduction, cytokine suppression level).',
    `publication_references` STRING COMMENT 'Comma-separated list of PubMed IDs, DOIs, or internal report identifiers for published or internal literature supporting the target validation findings (e.g., PMID:12345678, DOI:10.1016/...).',
    `selectivity_profile` STRING COMMENT 'Description of the targets selectivity relative to related family members or off-target proteins, informing safety and specificity risk assessment during early discovery.',
    `species` STRING COMMENT 'Biological species used in the model system for the validation study. Critical for translational relevance assessment and regulatory species concordance requirements.. Valid values are `Homo sapiens|Mus musculus|Rattus norvegicus|Macaca fascicularis|other`',
    `study_completion_date` DATE COMMENT 'The date on which all experimental work and data analysis for the target validation study were completed and the final study report was issued.',
    `study_number` STRING COMMENT 'Externally-known, human-readable business identifier for the target validation study, assigned at study initiation (e.g., TVS-EGFR-2024). Used for cross-system referencing in IDBS/Dotmatics ELN and CTMS.. Valid values are `^TVS-[A-Z0-9]{4,12}-[0-9]{4}$`',
    `study_outcome` STRING COMMENT 'Overall scientific conclusion of the target validation study, indicating whether the target has been confirmed as suitable for drug intervention in the specified disease context.. Valid values are `validated|not_validated|partially_validated|inconclusive|ongoing`',
    `study_start_date` DATE COMMENT 'The date on which experimental work for the target validation study formally commenced, as recorded in the ELN.',
    `study_status` STRING COMMENT 'Current lifecycle status of the target validation study, tracking progression from planning through completion or termination.. Valid values are `planned|in_progress|completed|on_hold|terminated|archived`',
    `study_title` STRING COMMENT 'Descriptive title of the target validation study, summarising the target, disease context, and primary validation approach (e.g., KRAS G12C Genetic Knockdown in NSCLC Cell Lines).',
    `target_class` STRING COMMENT 'Pharmacological class of the molecular target, used to guide druggability assessment and modality selection. [ENUM-REF-CANDIDATE: kinase|GPCR|nuclear_receptor|ion_channel|protease|epigenetic|transcription_factor|other — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this target validation study record was most recently modified, supporting change tracking and audit trail requirements under 21 CFR Part 11.',
    `validation_evidence_level` STRING COMMENT 'Qualitative assessment of the strength of evidence supporting the targets role in disease, based on reproducibility, model translatability, and mechanistic clarity. Drives go/no-go investment decisions.. Valid values are `strong|moderate|weak|inconclusive`',
    `validation_method` STRING COMMENT 'Primary experimental method used to validate the targets role in disease biology. [ENUM-REF-CANDIDATE: genetic_knockdown|genetic_knockout|overexpression|chemical_probe|patient_genetics|CRISPR_editing|RNAi|antisense_oligonucleotide — promote to reference product]',
    CONSTRAINT pk_target_validation_study PRIMARY KEY(`target_validation_study_id`)
) COMMENT 'Transactional record for studies conducted to validate a molecular targets role in disease and its suitability for drug intervention. Captures target identifier, validation method (genetic knockdown/knockout, overexpression, chemical probe, patient genetics), model system used (cell line, animal model, patient-derived), validation evidence level (strong, moderate, weak), disease linkage evidence, publication references, study outcome, validation scientist, and study completion date. Supports go/no-go decisions on target investment.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`in_vitro_study` (
    `in_vitro_study_id` BIGINT COMMENT 'Unique surrogate identifier for each in vitro mechanistic or safety study record in the discovery domain. Primary key for this entity.',
    `assay_id` BIGINT COMMENT 'Foreign key linking to discovery.assay. Business justification: In vitro mechanistic and safety studies use specific assays to measure compound activity. The study table currently has assay_format and assay_technology as denormalized STRING attributes. Adding assa',
    `compound_id` BIGINT COMMENT 'Reference to the compound (NCE or NBE) under investigation in this study, as registered in the compound library. Links to the compound master record for structure, molecular weight, and registration data.',
    `employee_id` BIGINT COMMENT 'Reference to the scientist responsible for designing and executing this in vitro study. Used for accountability, GLP audit trail, and scientific ownership tracking.',
    `gxp_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.gxp_obligation. Business justification: In vitro studies used for regulatory submissions must comply with GLP obligations. Obligation assignment determines validation requirements, data integrity controls, and inspection readiness for study',
    `molecular_target_id` BIGINT COMMENT 'Reference to the biological molecular target (protein, receptor, enzyme, pathway node) that this study is designed to interrogate. Links to the target identification master record.',
    `project_id` BIGINT COMMENT 'Reference to the drug discovery project under which this in vitro study is conducted. Enables aggregation of study results at the programme level for hit-to-lead and lead optimisation decisions.',
    `protocol_id` BIGINT COMMENT 'Reference to the approved study protocol document governing this in vitro study. Ensures traceability to the authorised experimental procedure and version.',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: In vitro studies (safety pharmacology, genotoxicity, receptor binding) are submitted in Module 4 of eCTD. Real regulatory requirement: nonclinical study reports with full traceability to submissions f',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: In vitro studies commonly outsourced to CRO vendors. Procurement manages vendor qualification, quality agreements, GLP compliance verification, data integrity oversight, and regulatory submission requ',
    `assay_z_prime_factor` DECIMAL(18,2) COMMENT 'Z-factor statistical metric quantifying assay quality and separation between positive and negative controls (range 0–1; values ≥0.5 indicate an excellent assay). Required for HTS and in vitro assay quality acceptance.',
    `biological_system_type` STRING COMMENT 'Category of the biological system used in the study. Determines the physiological relevance, regulatory acceptance, and interpretation framework for the results.. Valid values are `cell_line|primary_cells|organoid|tissue_slice|membrane_prep|recombinant_enzyme`',
    `cell_line_name` STRING COMMENT 'Specific name or designation of the cell line, primary cell type, organoid model, or other biological system used (e.g., HeLa, HepG2, Caco-2, iPSC-derived hepatocytes). Essential for scientific reproducibility and cross-study comparability.',
    `cell_line_passage_number` STRING COMMENT 'Number of times the cell line has been subcultured since its original isolation or receipt. High passage numbers can affect cell behaviour and result validity; tracked for quality and reproducibility.',
    `compound_batch_number` STRING COMMENT 'Specific batch or lot identifier of the compound used in this study. Critical for reproducibility, traceability, and investigation of batch-to-batch variability in results.',
    `concentration_max_nm` DECIMAL(18,2) COMMENT 'Highest concentration of the compound tested in this study, expressed in nanomolar (nM). Defines the upper bound of the concentration-response range; used to assess ceiling effects and cytotoxicity thresholds.',
    `concentration_min_nm` DECIMAL(18,2) COMMENT 'Lowest concentration of the compound tested in this study, expressed in nanomolar (nM). Defines the lower bound of the concentration-response range used for dose-response modelling.',
    `concentration_point_count` STRING COMMENT 'Number of distinct concentration levels tested in the dose-response series. Indicates the resolution of the concentration-response curve and the robustness of derived potency estimates.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this in vitro study record was first created in the system. Part of the GLP-required audit trail for electronic records per 21 CFR Part 11.',
    `cytotoxicity_flag` BOOLEAN COMMENT 'Indicates whether cytotoxic effects were observed at the tested concentration range. A True value signals that the primary endpoint result may be confounded by non-specific cell death and requires scientific interpretation caution.',
    `cytotoxicity_threshold_nm` DECIMAL(18,2) COMMENT 'Concentration in nanomolar at which cytotoxic effects were first observed (CC50 or NOEC for cytotoxicity). Used to define the safe concentration window for interpreting mechanistic results.',
    `data_quality_flag` STRING COMMENT 'Scientific data quality assessment status for this study result. Flagged or rejected results are excluded from SAR analysis and compound progression decisions pending investigation.. Valid values are `accepted|flagged|rejected|under_review`',
    `eln_notebook_reference` STRING COMMENT 'Reference identifier linking this study record to the corresponding experiment entry in the Electronic Lab Notebook (IDBS E-WorkBook or Dotmatics). Provides the authoritative source of raw data and experimental narrative.',
    `endpoint_type` STRING COMMENT 'Type of pharmacological or toxicological endpoint measured in this study (e.g., IC50 for inhibitory concentration, EC50 for effective concentration, Ki for inhibition constant, CC50 for cytotoxic concentration). Governs result interpretation and SAR analysis. [ENUM-REF-CANDIDATE: ic50|ec50|ki|cc50|emax|hill_slope|percent_inhibition|ld50|td50|pec50 — promote to reference product]',
    `glp_compliant_flag` BOOLEAN COMMENT 'Indicates whether this in vitro study was conducted in full compliance with Good Laboratory Practice (GLP) regulations. GLP-compliant studies are required for regulatory submissions supporting IND/NDA/BLA applications.',
    `incubation_temperature_c` DECIMAL(18,2) COMMENT 'Temperature in degrees Celsius at which the compound was incubated with the biological system. Deviations from protocol-specified temperature can invalidate results.',
    `incubation_time_hours` DECIMAL(18,2) COMMENT 'Duration of compound incubation with the biological system prior to endpoint measurement, expressed in hours. Affects the pharmacological and toxicological outcome; standardised per protocol.',
    `lims_sample_code` STRING COMMENT 'Sample identifier assigned by the LIMS (LabWare or Thermo Fisher SampleManager) for the compound sample used in this study. Enables traceability from study result back to sample preparation, storage, and chain of custody.',
    `moa_confirmed_flag` BOOLEAN COMMENT 'Indicates whether this study confirmed the hypothesised mechanism of action (MOA) for the compound at the tested target. A True value supports progression to the next stage of hit-to-lead development.',
    `positive_control_result` DECIMAL(18,2) COMMENT 'Measured result value for the positive control compound included in this study run. Used to validate assay performance and confirm that the assay window is within acceptable limits.',
    `replicate_count` STRING COMMENT 'Number of independent experimental replicates performed for this study. Higher replicate counts increase statistical confidence; minimum thresholds are defined in the study protocol.',
    `result_confidence_interval` STRING COMMENT '95% confidence interval for the primary result value, expressed as a string range (e.g., 0.032-0.061 µM). Quantifies statistical uncertainty around the point estimate for SAR and progression decisions.',
    `result_qualifier` STRING COMMENT 'Relational qualifier for the result value indicating whether the measurement is exact, a lower bound, or an upper bound (e.g., > for greater than, < for less than). Used when the true value falls outside the assay detection range.. Valid values are `=|<|>|<=|>=`',
    `result_unit` STRING COMMENT 'Unit of measurement for the primary result value (e.g., nM, µM, %, fold-change). Required for correct scientific interpretation and cross-study comparability.. Valid values are `nM|uM|mM|percent|fold_change|ratio`',
    `result_value` DECIMAL(18,2) COMMENT 'Numeric value of the primary pharmacological or toxicological endpoint measured in this study (e.g., IC50 = 0.045 µM). The principal quantitative outcome used for SAR analysis and compound progression decisions.',
    `selectivity_ratio` DECIMAL(18,2) COMMENT 'Ratio of the cytotoxicity threshold (CC50) to the primary pharmacological potency endpoint (IC50/EC50). A higher ratio indicates greater selectivity for the intended target over non-specific cytotoxic effects. Key SAR metric for compound progression.',
    `study_date` DATE COMMENT 'Calendar date on which the in vitro study experiment was physically conducted. Distinct from the record creation timestamp; used for scientific timeline tracking and GLP audit trail.',
    `study_number` STRING COMMENT 'Externally-known, human-readable unique study identifier assigned by the ELN (IDBS E-WorkBook or Dotmatics) or LIMS at study initiation. Used for cross-system traceability and regulatory reference. Format: IVS-<ProjectCode>-<SequenceNumber>.. Valid values are `^IVS-[A-Z0-9]{2,10}-[0-9]{4,8}$`',
    `study_status` STRING COMMENT 'Current lifecycle state of the in vitro study. Controls workflow progression from planning through execution to data review and archival.. Valid values are `planned|in_progress|completed|cancelled|on_hold`',
    `study_title` STRING COMMENT 'Descriptive title of the in vitro study summarising the scientific objective, biological system, and compound under investigation. Used for search, reporting, and scientific communication.',
    `study_type` STRING COMMENT 'Classification of the scientific purpose of the in vitro study. Drives protocol selection, endpoint interpretation, and regulatory categorisation. [ENUM-REF-CANDIDATE: mechanism_of_action|pathway_modulation|cell_viability|cytotoxicity|receptor_binding|enzyme_inhibition|genotoxicity|permeability|metabolic_stability — promote to reference product]. Valid values are `mechanism_of_action|pathway_modulation|cell_viability|cytotoxicity|receptor_binding|enzyme_inhibition`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this in vitro study record. Required for audit trail integrity under 21 CFR Part 11 and GLP regulations.',
    `vehicle_concentration_pct` DECIMAL(18,2) COMMENT 'Final concentration of the vehicle/solvent in the assay expressed as a percentage. Concentrations above accepted thresholds (e.g., >0.1% DMSO) can cause non-specific cytotoxicity or assay interference.',
    `vehicle_solvent` STRING COMMENT 'Solvent or vehicle used to dissolve and dilute the compound for testing (e.g., DMSO, PBS, ethanol). Solvent effects can confound results; tracked for quality control and reproducibility.',
    CONSTRAINT pk_in_vitro_study PRIMARY KEY(`in_vitro_study_id`)
) COMMENT 'Transactional record for in vitro mechanistic and safety studies conducted on selected compounds post-screening, including mechanism of action confirmation, pathway modulation, cell viability, and early cytotoxicity assessments. Captures study type, biological system (cell line, primary cells, organoids), compound and concentration range, endpoint measured, result values, cytotoxicity flag, protocol reference, GLP compliance flag, study date, and responsible scientist. Distinct from screening_result: in_vitro_study covers hypothesis-driven follow-up studies on prioritized compounds rather than high-throughput screening at scale.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`in_vivo_study` (
    `in_vivo_study_id` BIGINT COMMENT 'Unique surrogate identifier for the in vivo animal study record within the discovery domain lakehouse. Primary key for this entity.',
    `compound_id` BIGINT COMMENT 'Reference to the compound (New Chemical Entity or New Biological Entity) under investigation in this study, as registered in the compound library or ELN (IDBS/Dotmatics). Links to the authoritative compound master record.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: In vivo studies are major cost drivers requiring cost center allocation for animal care, facility costs, and study execution. Critical for pharmacology budget management, project costing, and financia',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: In vivo studies are high-cost activities requiring dedicated internal order tracking for budget management, CRO invoice reconciliation, program cost analysis, and candidate selection economics in phar',
    `molecular_target_id` BIGINT COMMENT 'Foreign key linking to discovery.molecular_target. Business justification: In vivo studies test compounds against specific molecular targets to assess target engagement and efficacy in animal models. Adding molecular_target_id FK establishes the link to the target master rec',
    `project_id` BIGINT COMMENT 'Foreign key linking to discovery.discovery_project. Business justification: In vivo animal studies are conducted within discovery projects to assess compound efficacy and PK. Currently in_vivo_study only links to compound but lacks project context. Adding discovery_project_id',
    `regulatory_inspection_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_inspection. Business justification: GLP-compliant in vivo studies are subject to regulatory inspections (FDA, EMA). Inspection linkage enables tracking of study-specific observations, Form 483 responses, and CAPA requirements for precli',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: GLP compliance mandates study director accountability with traceable qualifications. FDA inspections verify study director training, experience, and authority. FK to employee enables verification of G',
    `animal_count` STRING COMMENT 'Total number of animals used across all dose groups in the study. Required for IACUC protocol compliance, 3Rs (Replacement, Reduction, Refinement) reporting, and statistical power justification.',
    `animal_sex` STRING COMMENT 'Sex of the animals used in the study (male, female, or both sexes). Relevant for sex-specific PK/PD differences, hormonal effects, and regulatory requirements for balanced study design.. Valid values are `male|female|both`',
    `animal_species` STRING COMMENT 'Species of animal used in the in vivo study (e.g., mouse, rat, dog, non-human primate). Determines applicable regulatory guidelines, PK/PD scaling factors, and IACUC protocol requirements. [ENUM-REF-CANDIDATE: mouse|rat|rabbit|dog|monkey|minipig|hamster|guinea_pig — promote to reference product]',
    `animal_strain` STRING COMMENT 'Specific strain or substrain of the animal species used (e.g., C57BL/6 mouse, Sprague-Dawley rat, Beagle dog). Strain selection impacts pharmacological response, metabolic profile, and cross-study comparability.',
    `completion_date` DATE COMMENT 'Date on which the in vivo study was completed (last animal procedure, sample collection, or terminal endpoint). Null if the study is still in progress or was terminated early. Used for study report timelines and regulatory submission planning.',
    `compound_batch_number` STRING COMMENT 'Specific batch or lot number of the test article (compound) used in this study, as recorded in the LIMS or compound management system. Critical for traceability, reproducibility, and GLP compliance — links to Certificate of Analysis (CoA) for purity and characterization data.',
    `compound_identifier` STRING COMMENT 'Internal compound registration number or code (e.g., NCE/NBE identifier from the compound library) as assigned in the ELN or compound management system. Denormalized here for operational traceability without requiring a join. Classified confidential due to IP sensitivity.',
    `conducting_facility` STRING COMMENT 'Name of the facility (internal research site or external CRO/CMO) where the in vivo study was physically conducted. Relevant for multi-site studies, CRO oversight, and GLP facility qualification tracking.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this in vivo study record was first created in the system (ISO 8601 format with timezone offset). Audit trail field required for 21 CFR Part 11 electronic records compliance and data lineage tracking in the lakehouse silver layer.',
    `cro_flag` BOOLEAN COMMENT 'Indicates whether the study was outsourced to a Contract Research Organization (CRO) rather than conducted in-house. Drives CRO oversight workflows, contract management linkage, and sponsor responsibility documentation under GLP.',
    `dose_frequency` STRING COMMENT 'Frequency of compound administration during the study (e.g., single dose, once daily, twice daily). Defines the dosing regimen and is critical for PK/PD modeling and exposure calculations.. Valid values are `single_dose|once_daily|twice_daily|three_times_daily|weekly|biweekly`',
    `dose_levels` STRING COMMENT 'Comma-separated list of dose levels tested in the study (e.g., 1, 3, 10, 30 in the unit specified by dose_unit). Captures the full dose range including vehicle/control group. Stored as a structured string for multi-dose studies; individual dose group records are managed in the study design detail.',
    `dose_route` STRING COMMENT 'Route of compound administration to the animals (e.g., oral, intravenous, subcutaneous). Directly impacts bioavailability, PK profile, and translational relevance to the intended clinical route. [ENUM-REF-CANDIDATE: oral|intravenous|subcutaneous|intraperitoneal|intramuscular|inhalation|topical|intranasal — promote to reference product]',
    `dose_unit` STRING COMMENT 'Unit of measurement for dose levels administered in the study (e.g., mg/kg, µg/kg). Standardized unit required for cross-study comparability, allometric scaling, and regulatory submission.. Valid values are `mg/kg|ug/kg|mg/m2|nmol/kg|mg/mL`',
    `efficacy_endpoint` STRING COMMENT 'Description of the primary efficacy endpoint measured in the study (e.g., tumor volume reduction, blood glucose normalization, survival rate, biomarker inhibition percentage). Defines the scientific success criterion for the study and links to the compounds mechanism of action (MOA).',
    `efficacy_result_summary` STRING COMMENT 'Narrative summary of the primary efficacy outcome observed in the study (e.g., 60% tumor growth inhibition at 10 mg/kg QD, statistically significant reduction in target biomarker at all dose levels). Supports portfolio review and go/no-go decision-making.',
    `eln_notebook_reference` STRING COMMENT 'Reference identifier linking this study record to the corresponding experiment or notebook entry in the Electronic Lab Notebook system (IDBS E-WorkBook or Dotmatics). Provides traceability to raw experimental data, protocols, and observations recorded at the bench.',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether the study was conducted in full compliance with Good Laboratory Practice (GLP) regulations (21 CFR Part 58 / OECD GLP Principles). GLP-compliant studies are required for regulatory submissions (IND, NDA, BLA). Non-GLP studies are exploratory/screening studies.',
    `iacuc_approval_date` DATE COMMENT 'Date on which the IACUC protocol was formally approved, authorizing the commencement of animal studies. Study start_date must not precede this date. Critical for GLP compliance and regulatory audit readiness.',
    `iacuc_protocol_number` STRING COMMENT 'Unique protocol number assigned by the Institutional Animal Care and Use Committee (IACUC) approving the animal use in this study. Mandatory for all in vivo studies conducted in the US under the Animal Welfare Act and PHS Policy. Required for regulatory submissions and audit.',
    `lims_study_reference` STRING COMMENT 'Reference identifier linking this study record to the corresponding study or sample set in the LIMS (LabWare or Thermo Fisher SampleManager). Enables traceability of sample management, analytical results, and chain of custody for study samples.',
    `noael_mg_kg` DECIMAL(18,2) COMMENT 'No Observed Adverse Effect Level (NOAEL) determined from the study, expressed in mg/kg. The highest dose at which no statistically or biologically significant adverse effects were observed. Critical for safety margin calculations, human dose prediction, and IND-enabling study packages.',
    `pk_auc_ng_ml_h` DECIMAL(18,2) COMMENT 'Area Under the plasma concentration-time Curve (AUC) representing total systemic exposure to the compound, expressed in ng·mL⁻¹·h. Fundamental PK parameter for bioavailability assessment, dose proportionality analysis, and PK/PD modeling.',
    `pk_bioavailability_pct` DECIMAL(18,2) COMMENT 'Absolute oral bioavailability (%F) of the compound expressed as a percentage, calculated as the ratio of AUC after oral administration to AUC after intravenous administration. Critical for oral drug candidate selection and dose prediction.',
    `pk_clearance_ml_min_kg` DECIMAL(18,2) COMMENT 'Systemic clearance (CL) of the compound normalized to body weight (mL/min/kg). Represents the volume of plasma cleared of the compound per unit time. Key parameter for predicting human PK and first-in-human dose selection.',
    `pk_cmax_ng_ml` DECIMAL(18,2) COMMENT 'Maximum observed plasma concentration (Cmax) of the compound following administration, expressed in nanograms per milliliter (ng/mL). Key PK parameter for exposure assessment, dose-response modeling, and allometric scaling to human dose prediction.',
    `pk_half_life_h` DECIMAL(18,2) COMMENT 'Terminal elimination half-life (t½) of the compound in hours, representing the time required for plasma concentration to decrease by 50%. Used for dosing frequency determination, accumulation prediction, and species-to-human PK translation.',
    `pk_vd_l_kg` DECIMAL(18,2) COMMENT 'Apparent volume of distribution (Vd) of the compound normalized to body weight (L/kg). Indicates the extent of tissue distribution versus plasma binding. Critical for PK/PD modeling and human dose prediction via allometric scaling.',
    `principal_investigator` STRING COMMENT 'Full name of the Principal Investigator (PI) responsible for the scientific design and execution of the study. May differ from the Study Director in multi-site or CRO-conducted studies. Classified confidential as an internal personnel reference.',
    `start_date` DATE COMMENT 'Date on which the in vivo study was initiated (first animal dosing or first experimental procedure). The principal real-world event date for this study record. Used for timeline tracking, regulatory reporting, and study portfolio management.',
    `study_duration_days` STRING COMMENT 'Total planned duration of the in vivo study in calendar days from first dose to last observation/sample collection. Used for study planning, resource allocation, and regulatory classification (e.g., single-dose vs. repeat-dose toxicology).',
    `study_number` STRING COMMENT 'Externally-known, human-readable unique study identifier assigned by the research organization or LIMS (e.g., IDBS/Dotmatics ELN). Used for cross-referencing in regulatory submissions, study reports, and IACUC protocols. Follows the site-specific numbering convention.. Valid values are `^[A-Z]{2,6}-IVS-[0-9]{4}-[0-9]{4,6}$`',
    `study_phase` STRING COMMENT 'Drug discovery pipeline phase during which this in vivo study was conducted. Indicates the maturity of the compound under investigation and the decision gate this study supports (e.g., hit-to-lead progression, candidate selection).. Valid values are `hit_identification|hit_to_lead|lead_optimization|candidate_selection|preclinical`',
    `study_report_number` STRING COMMENT 'Unique identifier of the final GLP or non-GLP study report generated upon study completion. Used for cross-referencing in regulatory submissions (IND, NDA, BLA, eCTD), dossier compilation, and audit trail. Null until the study report is issued.',
    `study_status` STRING COMMENT 'Current lifecycle state of the in vivo study. Drives workflow routing, data lock decisions, and reporting eligibility. Terminated indicates early discontinuation with a documented reason; cancelled indicates the study was never initiated.. Valid values are `planned|in_progress|completed|terminated|on_hold|cancelled`',
    `study_title` STRING COMMENT 'Descriptive title of the in vivo study as recorded in the electronic lab notebook (ELN) or LIMS. Provides a human-readable summary of the study objective, compound, and species (e.g., Single-dose PK study of Compound XYZ-001 in Sprague-Dawley rats).',
    `study_type` STRING COMMENT 'Classification of the primary scientific objective of the in vivo study. Drives downstream data capture requirements and regulatory reporting pathways. [ENUM-REF-CANDIDATE: efficacy|pharmacokinetics|pharmacodynamics|tolerability|safety|pk_pd|dose_range_finding|moa — promote to reference product]',
    `termination_date` DATE COMMENT 'Date on which the study was prematurely terminated, if applicable. Distinct from completion_date (planned end). Populated only when study_status is terminated. Requires a corresponding termination_reason.',
    `termination_reason` STRING COMMENT 'Documented reason for early termination of the study (e.g., unexpected toxicity, compound supply failure, scientific decision to deprioritize). Required when termination_date is populated. Supports portfolio decision audit trail.',
    `tolerability_finding` STRING COMMENT 'Summary of tolerability observations recorded during the study, including body weight changes, clinical signs, and any adverse findings at tested dose levels. Informs the therapeutic index assessment and maximum tolerated dose (MTD) determination for candidate progression.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this in vivo study record (ISO 8601 format with timezone offset). Required for change tracking, audit compliance under 21 CFR Part 11, and incremental data pipeline processing in the Databricks lakehouse.',
    CONSTRAINT pk_in_vivo_study PRIMARY KEY(`in_vivo_study_id`)
) COMMENT 'Transactional record for in vivo animal studies conducted during discovery to assess compound efficacy, PK/PD relationships, and early tolerability. Captures study type (efficacy, PK, PD, tolerability), animal species and strain, study design (dose, route, frequency, duration), compound identifier, dose levels, PK parameters (Cmax, AUC, t1/2, Vd, CL), efficacy endpoints, tolerability observations, study status, GLP compliance flag, IACUC protocol number, study director, and study completion date.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`candidate_nomination` (
    `candidate_nomination_id` BIGINT COMMENT 'Unique system-generated identifier for the development candidate (DC) nomination record. Primary key for this transactional milestone event in the discovery-to-preclinical pipeline.',
    `compound_id` BIGINT COMMENT 'Reference to the nominated compound record in the compound library or ELN (IDBS E-WorkBook / Dotmatics). Links the nomination to the specific chemical or biological entity being advanced.',
    `hts_campaign_id` BIGINT COMMENT 'Reference to the High-Throughput Screening (HTS) campaign in LIMS (LabWare or SampleManager) from which the hit compound was originally identified prior to lead optimization. Provides full traceability from HTS hit to development candidate.',
    `inspection_readiness_id` BIGINT COMMENT 'Foreign key linking to compliance.inspection_readiness. Business justification: Candidate nominations trigger inspection readiness assessments for discovery sites/functions before IND filing. Readiness linkage drives mock inspections, gap remediation, and CAPA completion tracking',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Candidate nomination packages require cost tracking for the nomination process itself (committee meetings, documentation preparation, regulatory strategy) via internal orders for stage-gate cost analy',
    `lead_series_id` BIGINT COMMENT 'Reference to the lead chemical series from which the nominated development candidate was optimized. Supports Structure-Activity Relationship (SAR) traceability and series-level portfolio analysis.',
    `plant_id` BIGINT COMMENT 'Foreign key linking to masterdata.plant. Business justification: Candidate nominations assess manufacturing feasibility at specific plants for CMC planning, capacity assessment, and tech transfer readiness. Links discovery candidates to manufacturing infrastructure',
    `medicinal_product_id` BIGINT COMMENT 'Foreign key linking to product.medicinal_product. Business justification: R&D productivity tracking: links nominated development candidates to approved products for attrition analysis, success rate metrics, regulatory milestone tracking. Critical for stage-gate retrospectiv',
    `method_validation_id` BIGINT COMMENT 'Foreign key linking to quality.method_validation. Business justification: Candidate nomination triggers validation of analytical methods (potency, purity, identity) for the nominated compound. Method validation is a regulatory requirement for IND filing and ensures data qua',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Regulatory audit trails for IND submissions require traceable accountability for candidate nomination decisions. Links nominator to qualified employee record for verification of scientific authority, ',
    `patent_family_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_family. Business justification: Nominated candidates require robust patent protection assessment for IND readiness; patent family linkage supports IP due diligence, regulatory exclusivity strategy, and go/no-go decisions at nominati',
    `plan_id` BIGINT COMMENT 'Reference to the IND-enabling preclinical development plan created upon approved nomination. Links the nomination milestone to the downstream preclinical program and study schedule.',
    `project_id` BIGINT COMMENT 'Reference to the parent drug discovery project under which this candidate was identified and optimized. Links the nomination to the originating research program in the discovery portfolio.',
    `specification_id` BIGINT COMMENT 'Foreign key linking to quality.specification. Business justification: Candidate nomination establishes initial drug substance specifications (purity, potency, impurity limits) that are documented in quality systems and included in IND submissions. Specifications referen',
    `stability_study_id` BIGINT COMMENT 'Foreign key linking to quality.stability_study. Business justification: Candidate nomination triggers formal stability studies (ICH Q1A) as part of the IND-enabling package. Stability protocols reference the nomination to track regulatory commitments and support shelf-lif',
    `adme_pk_summary` STRING COMMENT 'Narrative summary of the compounds Absorption, Distribution, Metabolism, and Excretion (ADME) and Pharmacokinetics (PK) profile, including key parameters such as oral bioavailability, half-life, clearance, and metabolic stability. Critical for dose prediction and formulation strategy.',
    `cmc_feasibility_assessment` STRING COMMENT 'Assessment of the Chemistry, Manufacturing, and Controls (CMC) feasibility for the nominated compound, evaluating synthetic accessibility, scalability, and formulation developability. Informs manufacturing strategy and go/no-go decision.. Valid values are `feasible|feasible_with_risk|not_feasible|under_assessment`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the candidate nomination record was first created in the system. Supports audit trail requirements under 21 CFR Part 11 and data lineage tracking in the Databricks Silver layer.',
    `decision_date` DATE COMMENT 'Date on which the nomination committee rendered its formal decision (approved, deferred, or rejected) on the development candidate nomination. May differ from nomination_date if committee review takes multiple sessions.',
    `deferral_reason` STRING COMMENT 'Documented rationale for deferral or rejection of the development candidate nomination, capturing the scientific, safety, CMC, IP, or strategic basis for the committees decision. Required for governance records and future re-nomination consideration.',
    `efficacy_summary` STRING COMMENT 'Narrative summary of key in vitro and in vivo efficacy data supporting the nomination, including primary pharmacology results from High-Throughput Screening (HTS) and lead optimization assays. Sourced from LIMS and ELN records.',
    `eln_notebook_reference` STRING COMMENT 'Reference identifier linking to the primary Electronic Lab Notebook (ELN) experiment or project record in IDBS E-WorkBook or Dotmatics that contains the supporting scientific data for this nomination. Ensures data provenance and GLP traceability.',
    `estimated_ind_date` DATE COMMENT 'Projected target date for filing the Investigational New Drug (IND) application with the FDA (or equivalent CTA with EMA/MHRA) based on the approved nomination and preclinical development plan. Key pipeline milestone for portfolio planning.',
    `first_in_class` BOOLEAN COMMENT 'Indicates whether the nominated development candidate represents a first-in-class mechanism of action with no approved drugs acting on the same molecular target. Informs competitive positioning, IP strategy, and regulatory designation eligibility.',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether the key safety and pharmacology studies supporting this nomination were conducted in compliance with Good Laboratory Practice (GLP) regulations. GLP compliance is required for IND-enabling studies submitted to regulatory authorities.',
    `handoff_date` DATE COMMENT 'Date on which the nominated development candidate was formally handed off to the preclinical development team. Marks the transition from discovery to preclinical and initiates IND-enabling studies planning.',
    `ip_status` STRING COMMENT 'Current status of intellectual property protection for the nominated development candidate, including patent filing status and Freedom-to-Operate (FTO) assessment outcome. Confidential business data critical for portfolio valuation and licensing strategy.. Valid values are `patent_filed|patent_pending|patent_granted|no_patent|fto_clear|fto_risk_identified`',
    `moa_summary` STRING COMMENT 'Narrative summary of the compounds Mechanism of Action (MOA) — how it interacts with the molecular target to produce the desired pharmacological effect. Sourced from ELN (IDBS/Dotmatics) and used in IND applications and regulatory submissions.',
    `modality` STRING COMMENT 'The drug modality class of the nominated development candidate, distinguishing New Chemical Entities (NCE) from New Biological Entities (NBE) and advanced therapy types. Determines regulatory pathway (NDA vs BLA) and CMC strategy.. Valid values are `small_molecule|biologic|antibody|cell_therapy|gene_therapy|oligonucleotide`',
    `molecular_target` STRING COMMENT 'The biological macromolecule (protein, receptor, enzyme, nucleic acid) that the nominated compound is designed to modulate. Central to target identification and Mechanism of Action (MOA) characterization (e.g., EGFR, PD-1, BRAF, JAK1).',
    `nce_nbe_classification` STRING COMMENT 'Classification of the nominated compound as a New Chemical Entity (NCE) — a small molecule not previously approved — or a New Biological Entity (NBE) — a biologic not previously approved. Determines regulatory exclusivity, data protection, and CMC requirements.. Valid values are `NCE|NBE`',
    `nomination_committee` STRING COMMENT 'Name or identifier of the governance committee responsible for reviewing and rendering the nomination decision (e.g., Drug Discovery Committee, Portfolio Review Board, R&D Leadership Team). Supports governance traceability.',
    `nomination_date` DATE COMMENT 'The formal calendar date on which the development candidate was officially nominated for progression from discovery into preclinical development. This is the principal business event date for this milestone record.',
    `nomination_number` STRING COMMENT 'Externally-known, human-readable business identifier for the development candidate nomination (e.g., DC-ONCO-2024-0042). Used in cross-functional communications, regulatory filings, and portfolio tracking systems such as IDBS/Dotmatics ELN.. Valid values are `^DC-[A-Z]{2,6}-[0-9]{4}-[0-9]{4}$`',
    `nomination_status` STRING COMMENT 'Current lifecycle status of the development candidate nomination decision made by the nomination committee. Drives pipeline progression and resource allocation decisions. [ENUM-REF-CANDIDATE: approved|deferred|rejected|pending_review|withdrawn — promote to reference product if additional statuses are required]. Valid values are `approved|deferred|rejected|pending_review|withdrawn`',
    `orphan_drug_eligible` BOOLEAN COMMENT 'Indicates whether the nominated development candidate is potentially eligible for Orphan Drug Designation (ODD) based on the proposed indication affecting fewer than 200,000 patients in the US (or equivalent EU criteria). Triggers early regulatory strategy planning.',
    `portfolio_priority` STRING COMMENT 'Strategic priority classification assigned to the nominated development candidate by the R&D portfolio governance committee, reflecting unmet medical need, competitive landscape, commercial potential, and scientific confidence. Drives resource allocation.. Valid values are `high|medium|low`',
    `proposed_indication` STRING COMMENT 'The specific disease or clinical condition for which the development candidate is proposed to be developed (e.g., Non-Small Cell Lung Cancer, Rheumatoid Arthritis, Sickle Cell Disease). Informs IND strategy and regulatory pathway selection.',
    `regulatory_pathway` STRING COMMENT 'Anticipated regulatory approval pathway for the development candidate based on the proposed indication and unmet medical need (e.g., Standard, Fast Track, Breakthrough Therapy Designation, Accelerated Approval). Drives regulatory strategy and timeline planning.. Valid values are `standard|fast_track|breakthrough_therapy|accelerated_approval|priority_review`',
    `safety_summary` STRING COMMENT 'Narrative summary of early safety and tolerability findings from in vitro toxicology screens, genotoxicity assays, and any preliminary in vivo safety studies conducted under Good Laboratory Practice (GLP). Informs risk assessment for IND-enabling studies.',
    `selectivity_profile` STRING COMMENT 'Summary of the compounds selectivity against the primary target versus off-target proteins or receptors, derived from selectivity panel screening (e.g., kinase panel, GPCR panel). Informs safety risk and differentiation strategy.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this candidate nomination record originated or was primarily authored (e.g., IDBS E-WorkBook, Dotmatics, LIMS). Supports data lineage and Silver layer provenance tracking in the Databricks Lakehouse.. Valid values are `IDBS|Dotmatics|LIMS_LabWare|LIMS_SampleManager|manual`',
    `target_patient_population` STRING COMMENT 'Description of the intended patient population for the proposed indication, including relevant biomarker stratification, disease stage, or demographic characteristics (e.g., adult patients with EGFR-mutant NSCLC, pediatric patients with SMA). Informs clinical trial design.',
    `therapeutic_area` STRING COMMENT 'The disease or medical specialty area that the nominated development candidate is intended to address (e.g., Oncology, Immunology, Rare Diseases, Cardiovascular, Neuroscience). Drives portfolio segmentation and resource allocation. [ENUM-REF-CANDIDATE: oncology|immunology|rare_disease|cardiovascular|neuroscience|infectious_disease — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the candidate nomination record. Required for change tracking, audit compliance under 21 CFR Part 11, and incremental data pipeline processing.',
    CONSTRAINT pk_candidate_nomination PRIMARY KEY(`candidate_nomination_id`)
) COMMENT 'Transactional record capturing the formal nomination of a development candidate (DC) compound for progression from discovery into preclinical development. Captures nominated compound identifier, lead series identifier, discovery project identifier, nomination date, therapeutic area, target, proposed indication, key efficacy data summary, key safety data summary, ADME/PK profile summary, IP status, CMC feasibility assessment, nomination decision (approved, deferred, rejected), decision committee, and handoff date to preclinical team. Critical milestone event linking discovery to clinical development pipeline.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`computational_model` (
    `computational_model_id` BIGINT COMMENT 'Unique surrogate identifier for the computational or in silico model record within the drug discovery data product. Primary key for the computational_model entity.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: CSV (Computer System Validation) and regulatory submissions require traceable model ownership to qualified employees. Model validation, change control, and periodic review processes depend on linking ',
    `molecular_target_id` BIGINT COMMENT 'Foreign key linking to discovery.molecular_target. Business justification: Computational models (QSAR, pharmacophore, docking, PK/PD) are built for specific molecular targets. The model table currently has target_name as a denormalized STRING attribute. Adding molecular_targ',
    `project_id` BIGINT COMMENT 'Foreign key linking to discovery.discovery_project. Business justification: Computational models are developed within discovery projects to support drug discovery decisions. The model table currently has discovery_programme_code as a denormalized STRING attribute. Adding disc',
    `submission_id` BIGINT COMMENT 'Foreign key linking to regulatory.submission. Business justification: Computational models (PBPK, QSP, QSAR) increasingly submitted to support dosing rationale and safety assessments. Real regulatory trend: FDA/EMA encourage model-informed drug development (MIDD). Model',
    `algorithm` STRING COMMENT 'The computational or machine learning algorithm used to build the model (e.g., Random Forest, Support Vector Machine, Deep Neural Network, Glide SP docking, Gaussian Process Regression). Essential for reproducibility and scientific peer review.',
    `applicability_domain_description` STRING COMMENT 'Narrative or technical description of the chemical space within which the model is considered reliable (e.g., MW 150–600 Da, logP -2 to 5, Tanimoto similarity ≥0.4 to training set). Mandatory for OECD-compliant QSAR models; guides scientists on when predictions are trustworthy.',
    `auc_roc` DECIMAL(18,2) COMMENT 'Area Under the Receiver Operating Characteristic Curve performance metric for classification models (range 0.0–1.0). Primary discriminatory performance indicator for virtual screening and ADMET classification models.',
    `compartment_structure` STRING COMMENT 'Pharmacokinetic compartment structure of the model (e.g., one_compartment, two_compartment, physiologically_based). Applicable to PK/PD and ADME prediction models. Null or not_applicable for QSAR and docking models.. Valid values are `one_compartment|two_compartment|three_compartment|physiologically_based|non_compartmental|not_applicable`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the computational model record was first created in the data platform. Supports audit trail, data lineage, and 21 CFR Part 11 electronic record compliance.',
    `cross_validation_folds` STRING COMMENT 'Number of folds used in k-fold cross-validation during model training and internal validation (e.g., 5, 10). Null if cross-validation was not used. Supports reproducibility and scientific peer review.',
    `deployment_date` DATE COMMENT 'Date on which the model was first deployed to a production or internal scientific environment for active use in compound design or screening decisions.',
    `deployment_status` STRING COMMENT 'Operational deployment state of the model within the computational chemistry or pharmacometrics platform. Distinguishes models available for active compound scoring from those under development or retired.. Valid values are `not_deployed|deployed_internal|deployed_production|deprecated`',
    `ec50` DECIMAL(18,2) COMMENT 'Concentration producing 50% of the maximum pharmacodynamic effect (EC50) in the PK/PD model, expressed in molar or mass concentration units. Key parameter for dose selection and therapeutic window assessment.',
    `eln_reference` STRING COMMENT 'Reference identifier linking this model to the corresponding experiment or notebook entry in the ELN system (IDBS E-WorkBook or Dotmatics). Provides traceability from the model record back to the primary scientific data and experimental context.',
    `emax` DECIMAL(18,2) COMMENT 'Maximum pharmacodynamic effect (Emax) parameter from a PK/PD model, expressed in the units of the pharmacodynamic endpoint. Applicable only to PK/PD and pharmacometric models; null for QSAR or docking models.',
    `enrichment_factor` DECIMAL(18,2) COMMENT 'Enrichment factor at a defined percentage of the ranked library (e.g., EF1% or EF5%) for virtual screening models. Measures the models ability to prioritise active compounds over inactives. Critical for HTS triage decisions.',
    `hill_coefficient` DECIMAL(18,2) COMMENT 'Hill coefficient (n or γ) describing the steepness of the concentration-effect relationship in the Emax model. Values >1 indicate cooperative binding; values <1 indicate negative cooperativity. Applicable to PK/PD models only.',
    `is_glp_compliant` BOOLEAN COMMENT 'Indicates whether the model and its supporting data were generated under GLP (Good Laboratory Practice) conditions. GLP-compliant models may be used to support regulatory submissions including IND and NDA/BLA filings.',
    `model_code` STRING COMMENT 'Externally-known, human-readable unique business identifier for the model (e.g., CM-QSAR0042). Used in scientific publications, ELN references, and cross-system traceability within IDBS E-WorkBook or Dotmatics.. Valid values are `^CM-[A-Z0-9]{4,12}$`',
    `model_description` STRING COMMENT 'Free-text scientific description of the models purpose, scope, key assumptions, and intended use cases within the drug discovery workflow. Provides context for scientists and regulatory reviewers.',
    `model_name` STRING COMMENT 'Descriptive human-readable name of the computational model (e.g., EGFR Kinase QSAR Model v2, ADMET Solubility Predictor). Used as the primary display label in scientific dashboards and model registries.',
    `model_status` STRING COMMENT 'Current lifecycle state of the computational model. Controls whether the model may be used for active compound design decisions. Validated and deployed models are authoritative for NCE/NBE progression decisions.. Valid values are `draft|in_validation|validated|deployed|retired|superseded`',
    `model_type` STRING COMMENT 'Classification of the computational model by its scientific methodology. Drives downstream routing to appropriate validation workflows and performance benchmarks. [ENUM-REF-CANDIDATE: QSAR|molecular_docking|virtual_screening|pharmacophore|PKPD|ADMET|AI_ML_property|scaffold_hopping|free_energy_perturbation|other — promote to reference product]',
    `model_version` STRING COMMENT 'Semantic version number of the model (e.g., 1.0, 2.3.1). Enables tracking of model evolution, retraining cycles, and reproducibility of predictions across drug discovery campaigns.. Valid values are `^[0-9]+.[0-9]+(.[0-9]+)?$`',
    `molecular_descriptor_set` STRING COMMENT 'Name or description of the molecular descriptor set or fingerprint type used as model input features (e.g., ECFP4 Morgan fingerprints, RDKit 2D descriptors, MACCS keys, 3D pharmacophore features). Required for OECD QSAR Principle 2 (unambiguous algorithm definition).',
    `owning_team` STRING COMMENT 'Name of the scientific team or department responsible for the model (e.g., Computational Chemistry, Pharmacometrics, AI Drug Design). Supports organisational accountability and model governance reporting.',
    `predicted_property` STRING COMMENT 'The specific biological, physicochemical, or pharmacokinetic property or endpoint the model predicts (e.g., pIC50 vs EGFR, aqueous solubility (logS), human hepatic clearance, hERG inhibition). Central to model cataloguing and scientific search.',
    `publication_reference` STRING COMMENT 'DOI, PubMed ID, or internal report number of the scientific publication or technical report describing the model methodology and validation. Supports IP management, scientific credibility, and regulatory submission traceability.',
    `r_squared` DECIMAL(18,2) COMMENT 'R-squared (coefficient of determination) for regression models, measuring the proportion of variance in the predicted property explained by the model. Reported on the external test set per OECD guidelines.',
    `retirement_date` DATE COMMENT 'Date on which the model was retired or superseded and is no longer authoritative for compound design decisions. Null if the model is still active. Supports lifecycle governance and audit trail.',
    `rmse` DECIMAL(18,2) COMMENT 'Root Mean Square Error of prediction on the test set for regression models. Primary accuracy metric for QSAR regression and PK/PD parameter prediction models. Units match the predicted property.',
    `software_platform` STRING COMMENT 'Name and version of the computational software or platform used to build and run the model (e.g., Schrödinger Suite 2023-3, RDKit 2023.09, MOE 2022.02, KNIME 4.7, Python 3.10 / scikit-learn 1.3). Required for CSV (Computer System Validation) and reproducibility.',
    `test_set_size` STRING COMMENT 'Number of compounds or data points in the external test/validation dataset used to assess model generalisability. Distinct from training set; required for OECD-compliant QSAR validation.',
    `therapeutic_area` STRING COMMENT 'Therapeutic area or disease indication for which the model was developed (e.g., Oncology, Immunology, Rare Diseases, Neuroscience). Enables portfolio-level analytics and resource allocation across drug discovery programmes.',
    `training_dataset_name` STRING COMMENT 'Name or identifier of the dataset used to train the model (e.g., ChEMBL34_EGFR_IC50, Internal_HTS_2022_Q3). Supports data lineage, model reproducibility, and regulatory traceability per OECD QSAR principles.',
    `training_set_size` STRING COMMENT 'Number of compounds or data points in the training dataset. Key model quality indicator; small training sets flag potential overfitting risk during scientific review.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the computational model record. Required for change tracking, audit trail, and data synchronisation with source ELN and model registry systems.',
    `validation_method` STRING COMMENT 'Statistical or experimental method used to validate the models predictive performance (e.g., cross_validation, external_test_set, prospective validation). Determines regulatory acceptability of the model for decision-making.. Valid values are `cross_validation|external_test_set|prospective|leave_one_out|y_scrambling|none`',
    CONSTRAINT pk_computational_model PRIMARY KEY(`computational_model_id`)
) COMMENT 'Master record for computational and in silico models supporting drug discovery decisions. Covers QSAR, molecular docking, virtual screening, pharmacophore models, PK/PD models, ADMET prediction, and AI/ML property prediction. Captures model name, type, target or property predicted, algorithm, training dataset, performance metrics (AUC, RMSE, enrichment factor), PK/PD parameters (Emax, EC50, Hill coefficient, compartment structure) where applicable, validation status, software platform, model owner, and deployment status. Supports computational chemistry, pharmacometrics, and AI-driven compound design.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`compound_supply_agreement` (
    `compound_supply_agreement_id` BIGINT COMMENT 'Unique system-generated surrogate key for each compound-vendor supply agreement record',
    `compound_id` BIGINT COMMENT 'Foreign key linking to the compound being sourced from this vendor',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to the vendor supplying this compound',
    `agreement_effective_date` DATE COMMENT 'Date when the supply agreement for this compound-vendor combination became effective',
    `agreement_expiry_date` DATE COMMENT 'Date when the supply agreement for this compound-vendor combination expires and requires renewal or renegotiation',
    `agreement_status` STRING COMMENT 'Current lifecycle status of this compound-vendor supply agreement. Active: approved for procurement. Inactive: temporarily suspended. Pending: under negotiation. Expired: past expiry date. Terminated: permanently ended.',
    `catalog_number` STRING COMMENT 'Vendor-specific catalog number or SKU for this compound in the vendors product catalog. Used for purchase order line item specification.',
    `coa_required` BOOLEAN COMMENT 'Indicates whether a Certificate of Analysis (CoA) must be provided by the vendor with each shipment of this compound. CoA requirements vary by compound criticality and vendor qualification status.',
    `last_purchase_date` DATE COMMENT 'Date of the most recent purchase order placed for this compound from this vendor. Used to track active supply relationships and vendor performance history.',
    `last_quality_issue_date` DATE COMMENT 'Date of the most recent quality issue reported for this compound from this vendor',
    `lead_time_days` STRING COMMENT 'Number of business days from purchase order placement to delivery for this compound from this vendor. Lead time varies by vendor based on synthesis complexity, inventory availability, and shipping logistics.',
    `minimum_order_quantity` DECIMAL(18,2) COMMENT 'Minimum quantity (in grams, milligrams, or units) that must be ordered from this vendor for this compound. MOQ varies by vendor based on synthesis batch economics.',
    `minimum_order_quantity_uom` STRING COMMENT 'Unit of measure for the minimum order quantity (gram, milligram, kilogram, vial, unit)',
    `preferred_vendor_flag` BOOLEAN COMMENT 'Indicates whether this vendor is designated as the preferred supplier for this specific compound based on quality, price, reliability, and strategic relationship. A compound may have multiple approved vendors but only one preferred vendor.',
    `price_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the unit price (e.g., USD, EUR, GBP)',
    `purity_specification` STRING COMMENT 'Contractually agreed minimum purity specification for this compound from this vendor (e.g., ≥95%, ≥98%, ≥99.5%). Purity requirements may vary by vendor capability and intended use.',
    `quality_issue_count` STRING COMMENT 'Number of quality issues (out-of-specification results, failed CoA, contamination) reported for this compound from this vendor. Used for vendor performance tracking and sourcing decisions.',
    `unit_price` DECIMAL(18,2) COMMENT 'Negotiated price per unit (gram, milligram, or vial) for this compound from this vendor. Price varies by vendor based on volume commitments, purity specifications, and contract terms.',
    CONSTRAINT pk_compound_supply_agreement PRIMARY KEY(`compound_supply_agreement_id`)
) COMMENT 'This association product represents the supply contract between a discovery compound and a procurement vendor. It captures vendor-specific sourcing terms, pricing, quality specifications, and procurement logistics that exist only in the context of this compound-vendor relationship. Each record links one compound to one vendor with commercial and quality attributes negotiated for that specific supply arrangement.. Existence Justification: In pharmaceutical operations, a single compound can be sourced from multiple vendors to ensure supply security, optimize costs, and maintain regulatory redundancy (multi-sourcing strategy). Conversely, each vendor supplies multiple compounds across the discovery library. The business actively manages these supply relationships as distinct agreements, each with vendor-specific pricing, lead times, purity specifications, catalog numbers, and preferred vendor designations that cannot be stored on either the compound or vendor entity alone.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`compound_exposure` (
    `compound_exposure_id` BIGINT COMMENT 'Primary key for compound_exposure',
    `compound_id` BIGINT COMMENT 'Foreign key linking to the discovery compound that was administered to the patient. Identifies the specific investigational compound (NCE/NBE) used in this treatment exposure.',
    `investigational_product_id` BIGINT COMMENT 'Identifier of the specific investigational product formulation administered (links to clinical.investigational_product). Captures the drug product form, not just the compound.',
    `patient_id` BIGINT COMMENT 'Foreign key linking to the patient who received the compound. Identifies the clinical trial participant or patient in the treatment exposure record.',
    `trial_id` BIGINT COMMENT 'Identifier of the clinical trial protocol under which this compound exposure occurred. Links to clinical.trial for trial-level context.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this exposure record was created. Audit metadata for data lineage and compliance.',
    `discontinuation_reason` STRING COMMENT 'Primary reason why the patient discontinued treatment with this compound. Critical for safety analysis, efficacy assessment, and regulatory reporting.',
    `dose_level` STRING COMMENT 'Dose level or dosing regimen administered to the patient (e.g., 100mg QD, 5mg/kg Q2W). Captures the specific dosing schedule for this compound-patient exposure.',
    `enrollment_date` DATE COMMENT 'Date when the patient was enrolled into the treatment arm and began receiving the investigational compound. Critical for exposure duration calculation and safety reporting windows.',
    `exposure_status` STRING COMMENT 'Current lifecycle status of this compound exposure record (active, completed, discontinued, withdrawn). Tracks whether the patient is currently receiving treatment.',
    `response_category` STRING COMMENT 'Overall clinical response of the patient to the compound treatment, typically using standardized response criteria (e.g., RECIST for oncology). Captures efficacy outcome for this exposure.',
    `treatment_arm` STRING COMMENT 'Clinical trial treatment arm to which the patient was randomized or assigned (active, placebo, comparator, combination). Determines which compound or regimen the patient received.',
    `treatment_duration_days` STRING COMMENT 'Total duration of compound exposure expressed in days. Used for exposure-response analysis, safety signal detection, and pharmacovigilance reporting.',
    `treatment_end_date` DATE COMMENT 'Actual date of last dose administration of the compound to the patient. Used for exposure duration calculation and follow-up period determination.',
    `treatment_start_date` DATE COMMENT 'Actual date of first dose administration of the compound to the patient. Used for exposure window calculation and temporal safety analysis.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp when this exposure record was last updated. Audit metadata for change tracking.',
    CONSTRAINT pk_compound_exposure PRIMARY KEY(`compound_exposure_id`)
) COMMENT 'This association product represents the treatment exposure event between a discovery compound and a clinical trial patient. It captures the investigational use of a compound in a patient, including dosing regimen, treatment duration, clinical response, and discontinuation details. Each record links one compound to one patient in the context of a specific treatment episode within a clinical trial. This is the authoritative source for compound-patient exposure history across the discovery-to-clinical continuum.. Existence Justification: In pharmaceutical clinical development, one compound is tested in many patients across multiple trials and trial phases, and one patient may receive multiple investigational compounds either sequentially (across different trials) or simultaneously (in combination therapy trials). The business actively manages compound-patient exposure records as operational entities with treatment-specific data including dosing regimen, treatment duration, clinical response, and discontinuation reasons. This is a recognized business concept called compound exposure or treatment exposure that is critical for pharmacovigilance, efficacy analysis, and regulatory submissions.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`assay_panel` (
    `assay_panel_id` BIGINT COMMENT 'Primary key for assay_panel',
    `compound_library_id` BIGINT COMMENT 'Reference to the compound library typically screened using this panel.',
    `parent_assay_panel_id` BIGINT COMMENT 'Self-referencing FK on assay_panel (parent_assay_panel_id)',
    `assay_count` STRING COMMENT 'Total number of individual assays included in this panel.',
    `assay_protocol_version` STRING COMMENT 'Version number of the standard operating procedure or protocol used for this panel.',
    `cell_line` STRING COMMENT 'Specific cell line used in cell-based assays within this panel (e.g., HEK293, CHO, HeLa).',
    `cost_per_data_point` DECIMAL(18,2) COMMENT 'Average cost in USD to generate one data point using this assay panel, used for resource planning and prioritization.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this assay panel record was first created in the system.',
    `data_quality_score` DECIMAL(18,2) COMMENT 'Composite quality score (0-100) reflecting reproducibility, signal-to-noise ratio, and Z-factor for this panel.',
    `assay_panel_description` STRING COMMENT 'Detailed description of the assay panel including scientific rationale, target biology, and intended use cases.',
    `detection_method` STRING COMMENT 'Primary detection or readout technology used in the panel (e.g., fluorescence, luminescence, absorbance, mass spectrometry, imaging).',
    `effective_end_date` DATE COMMENT 'Date when this assay panel was retired or discontinued. Null if still active.',
    `effective_start_date` DATE COMMENT 'Date when this assay panel became operational and available for screening.',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether this assay panel is conducted under Good Laboratory Practice regulations.',
    `last_validation_date` DATE COMMENT 'Date of the most recent validation or revalidation of this assay panel under GLP standards.',
    `modified_by` STRING COMMENT 'User or system identifier that last modified this assay panel record.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this assay panel record was last modified.',
    `next_validation_due_date` DATE COMMENT 'Scheduled date for the next required validation or revalidation of this panel.',
    `notes` STRING COMMENT 'Additional notes, comments, or special considerations for this assay panel.',
    `owning_department` STRING COMMENT 'Department or research group that owns and maintains this assay panel.',
    `panel_code` STRING COMMENT 'Unique business identifier code for the assay panel used in laboratory information management systems and electronic lab notebooks.',
    `panel_name` STRING COMMENT 'Human-readable name of the assay panel describing its purpose or target.',
    `panel_status` STRING COMMENT 'Current lifecycle status of the assay panel indicating whether it is active for screening, under development, validated, or retired.',
    `panel_type` STRING COMMENT 'Classification of the assay panel by methodology or purpose (biochemical, cell-based, phenotypic, binding, functional, ADME, toxicity).',
    `plate_format` STRING COMMENT 'Standard microplate format used for this assay panel (96-well, 384-well, 1536-well, or other).',
    `primary_contact_scientist` STRING COMMENT 'Name of the principal scientist or researcher responsible for this assay panel.',
    `quality_control_frequency` STRING COMMENT 'Frequency at which quality control checks are performed on this assay panel to ensure data integrity and reproducibility.',
    `regulatory_submission_eligible` BOOLEAN COMMENT 'Indicates whether data from this panel can be included in regulatory submissions (IND, NDA, BLA).',
    `screening_stage` STRING COMMENT 'Drug discovery stage at which this panel is typically deployed (primary screening, secondary screening, tertiary screening, lead optimization, preclinical).',
    `species` STRING COMMENT 'Biological species from which assay components are derived (e.g., human, mouse, rat, cynomolgus monkey).',
    `target_class` STRING COMMENT 'Biological target class or family that the panel is designed to screen against (e.g., kinases, GPCRs, ion channels, proteases, nuclear receptors).',
    `therapeutic_area` STRING COMMENT 'Primary therapeutic area or disease category that this assay panel is designed to support (oncology, immunology, rare diseases, neurology, cardiovascular, metabolic).',
    `throughput_capacity` STRING COMMENT 'Screening throughput classification indicating the number of compounds that can be tested per unit time (low, medium, high, ultra-high throughput).',
    `turnaround_time_days` STRING COMMENT 'Typical turnaround time in days from sample submission to results delivery for this panel.',
    `validation_status` STRING COMMENT 'Validation state of the assay panel indicating whether it has passed required quality and reproducibility standards under GLP.',
    `created_by` STRING COMMENT 'User or system identifier that created this assay panel record.',
    CONSTRAINT pk_assay_panel PRIMARY KEY(`assay_panel_id`)
) COMMENT 'Master reference table for assay_panel. Referenced by assay_panel_id.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`synthesis_route` (
    `synthesis_route_id` BIGINT COMMENT 'Primary key for synthesis_route',
    `alternative_route_id` BIGINT COMMENT 'Reference to an alternative synthesis route for the same target compound, if one exists.',
    `compound_id` BIGINT COMMENT 'Reference to the target compound or New Chemical Entity (NCE) / New Biological Entity (NBE) that this synthesis route produces.',
    `project_id` BIGINT COMMENT 'Reference to the drug discovery project under which this synthesis route was developed.',
    `predecessor_synthesis_route_id` BIGINT COMMENT 'Self-referencing FK on synthesis_route (predecessor_synthesis_route_id)',
    `advantages` STRING COMMENT 'Summary of the key advantages of this synthesis route compared to alternative routes (e.g., higher yield, lower cost, fewer steps, better safety profile).',
    `analytical_methods` STRING COMMENT 'Analytical techniques used to characterize intermediates and final product (e.g., Nuclear Magnetic Resonance (NMR), High-Performance Liquid Chromatography (HPLC), Mass Spectrometry (MS)).',
    `complexity_score` STRING COMMENT 'Numerical score (typically 1-10) representing the technical complexity of the synthesis route based on reaction difficulty, purification challenges, and specialized equipment requirements.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this synthesis route record was first created in the system.',
    `critical_reagents` STRING COMMENT 'List of critical or specialized reagents required for key transformations in the synthesis route.',
    `eln_reference_code` STRING COMMENT 'Reference identifier linking this synthesis route to the corresponding entry in the Electronic Lab Notebook (ELN) system (IDBS/Dotmatics).',
    `environmental_impact_rating` STRING COMMENT 'Assessment of the environmental impact of the synthesis route considering waste generation, solvent usage, and energy consumption.',
    `estimated_cost_per_gram_usd` DECIMAL(18,2) COMMENT 'Estimated cost in United States Dollars (USD) to synthesize one gram of the target compound using this route, including materials, labor, and overhead.',
    `estimated_duration_days` STRING COMMENT 'Estimated total time in days required to complete the entire synthesis route from start to finish, including reaction times and purification.',
    `glp_compliant_flag` BOOLEAN COMMENT 'Indicates whether this synthesis route has been validated and documented according to Good Laboratory Practice (GLP) standards.',
    `hazard_classification` STRING COMMENT 'Overall safety hazard classification for the synthesis route based on reagent toxicity, reaction conditions, and handling requirements.',
    `inventor_name` STRING COMMENT 'Name of the primary chemist or research scientist who developed or discovered this synthesis route.',
    `key_reaction_types` STRING COMMENT 'Comma-separated list of the major chemical reaction types employed in this synthesis route (e.g., coupling, cyclization, reduction, oxidation).',
    `last_used_date` DATE COMMENT 'Date when this synthesis route was most recently executed in the laboratory or manufacturing facility.',
    `limitations` STRING COMMENT 'Summary of known limitations or challenges associated with this synthesis route (e.g., expensive reagents, difficult purification, poor scalability).',
    `mechanism_of_action` STRING COMMENT 'Description of the biological mechanism by which the synthesized compound exerts its therapeutic effect.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this synthesis route record was last modified or updated.',
    `overall_yield_percent` DECIMAL(18,2) COMMENT 'Cumulative yield percentage across all steps of the synthesis route, representing the efficiency of the entire synthetic pathway.',
    `patent_number` STRING COMMENT 'Primary patent number(s) protecting this synthesis route, if applicable. Multiple patents may be comma-separated.',
    `patent_protected_flag` BOOLEAN COMMENT 'Indicates whether this synthesis route is protected by one or more patents owned by or licensed to the organization.',
    `purification_methods` STRING COMMENT 'Primary purification techniques used in the synthesis route (e.g., chromatography, crystallization, distillation).',
    `route_code` STRING COMMENT 'Externally-known unique business identifier for the synthesis route, used across research and development systems.',
    `route_description` STRING COMMENT 'Detailed textual description of the synthesis route including key transformations, strategic considerations, and notable features.',
    `route_name` STRING COMMENT 'Human-readable name or title of the synthesis route, typically describing the key transformation or target molecule.',
    `route_status` STRING COMMENT 'Current lifecycle status of the synthesis route indicating its readiness and approval state for use in compound production.',
    `route_type` STRING COMMENT 'Classification of the synthesis route strategy (linear, convergent, divergent, parallel, combinatorial, or semi-synthesis).',
    `scalability_rating` STRING COMMENT 'Assessment of the synthesis routes suitability for scale-up from laboratory to pilot or commercial manufacturing.',
    `starting_material_availability` STRING COMMENT 'Assessment of the availability and sourcing ease for the key starting materials required for this synthesis route.',
    `therapeutic_area` STRING COMMENT 'Primary therapeutic area or disease category that the target compound addresses.',
    `total_steps` STRING COMMENT 'Total number of discrete chemical transformation steps required to complete this synthesis route from starting materials to final product.',
    `usage_count` STRING COMMENT 'Total number of times this synthesis route has been executed since its validation.',
    `validated_by` STRING COMMENT 'Name of the senior scientist or quality assurance personnel who validated this synthesis route.',
    `validated_date` DATE COMMENT 'Date when this synthesis route was formally validated and approved for use in compound production.',
    `version_number` STRING COMMENT 'Version number of this synthesis route, incremented when significant modifications are made to the route design or execution.',
    CONSTRAINT pk_synthesis_route PRIMARY KEY(`synthesis_route_id`)
) COMMENT 'Master reference table for synthesis_route. Referenced by synthesis_route_id.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`discovery`.`compound_library` (
    `compound_library_id` BIGINT COMMENT 'Primary key for compound_library',
    `employee_id` BIGINT COMMENT 'Reference to the principal scientist or researcher responsible for maintaining and managing this compound library.',
    `parent_compound_library_id` BIGINT COMMENT 'Self-referencing FK on compound_library (parent_compound_library_id)',
    `compound_count` STRING COMMENT 'Total number of unique chemical compounds currently contained in this library.',
    `concentration_mm` DECIMAL(18,2) COMMENT 'Standard concentration of compounds in the library expressed in millimolar (mM) units.',
    `created_date` DATE COMMENT 'Date when the compound library record was first created in the system.',
    `data_classification` STRING COMMENT 'Security classification level of the compound library data indicating access restrictions and handling requirements.',
    `compound_library_description` STRING COMMENT 'Detailed textual description of the compound library including its purpose, composition strategy, and intended research applications.',
    `diversity_score` DECIMAL(18,2) COMMENT 'Calculated chemical diversity score (0-100) indicating the structural variety within the library, higher scores represent greater diversity.',
    `druggability_score` DECIMAL(18,2) COMMENT 'Calculated score (0-100) indicating the likelihood that compounds in this library possess drug-like properties based on physicochemical parameters.',
    `glp_compliant` BOOLEAN COMMENT 'Indicates whether the compound library is maintained under Good Laboratory Practice standards for regulatory submissions.',
    `hit_rate_percent` DECIMAL(18,2) COMMENT 'Historical average percentage of compounds from this library that have been identified as hits in screening campaigns.',
    `intellectual_property_status` STRING COMMENT 'Legal intellectual property classification of the compound library indicating ownership and usage rights.',
    `last_modified_by` STRING COMMENT 'Name or identifier of the researcher or system user who last modified the compound library record.',
    `last_modified_date` DATE COMMENT 'Date when the compound library record was most recently updated or modified.',
    `last_quality_check_date` DATE COMMENT 'Date of the most recent quality control assessment performed on the compound library.',
    `library_code` STRING COMMENT 'Unique business identifier code for the compound library used across research systems and publications.',
    `library_name` STRING COMMENT 'Human-readable name of the compound library describing its purpose or composition.',
    `library_status` STRING COMMENT 'Current lifecycle status of the compound library indicating its availability for screening and research activities.',
    `library_type` STRING COMMENT 'Classification of the compound library based on its intended use and composition strategy in drug discovery.',
    `license_expiration_date` DATE COMMENT 'Date when the license agreement for externally sourced compound libraries expires, if applicable.',
    `mechanism_of_action` STRING COMMENT 'Intended or observed mechanism by which compounds in this library exert their biological effects.',
    `molecular_weight_range_max` DECIMAL(18,2) COMMENT 'Maximum molecular weight (in Daltons) of compounds in this library, used to characterize library composition.',
    `molecular_weight_range_min` DECIMAL(18,2) COMMENT 'Minimum molecular weight (in Daltons) of compounds in this library, used to characterize library composition.',
    `notes` STRING COMMENT 'Additional free-text notes or comments about the compound library for internal research team reference.',
    `plate_format` STRING COMMENT 'Physical format of the storage plates or containers used for the compound library.',
    `purity_threshold_percent` DECIMAL(18,2) COMMENT 'Minimum required purity percentage for compounds to be included in this library, typically determined by analytical methods.',
    `quality_check_status` STRING COMMENT 'Result of the most recent quality control assessment indicating compound integrity and purity.',
    `screening_campaign_count` STRING COMMENT 'Total number of high-throughput screening (HTS) campaigns in which this compound library has been utilized.',
    `screening_ready` BOOLEAN COMMENT 'Indicates whether the compound library is formatted, quality-controlled, and ready for high-throughput screening (HTS) campaigns.',
    `solvent_type` STRING COMMENT 'Primary solvent used for compound dissolution and storage in the library.',
    `source_type` STRING COMMENT 'Origin classification of the compound library indicating whether it was developed internally or acquired externally.',
    `storage_location` STRING COMMENT 'Physical or virtual location where the compound library is stored (e.g., freezer ID, vault location, cloud repository).',
    `storage_temperature_celsius` DECIMAL(18,2) COMMENT 'Required storage temperature in degrees Celsius to maintain compound stability and integrity.',
    `target_class` STRING COMMENT 'Primary biological target class that this compound library is designed to modulate (e.g., kinases, GPCRs, ion channels, proteases).',
    `therapeutic_area` STRING COMMENT 'Primary therapeutic area or disease indication that this compound library is designed to target (e.g., oncology, immunology, neurology, rare diseases).',
    `vendor_name` STRING COMMENT 'Name of the external vendor or supplier if the library was commercially acquired or licensed.',
    `created_by` STRING COMMENT 'Name or identifier of the researcher or system user who created the compound library record.',
    CONSTRAINT pk_compound_library PRIMARY KEY(`compound_library_id`)
) COMMENT 'Master reference table for compound_library. Referenced by compound_library_id.';

